INSERT INTO "API" VALUES (11,'[]','[''01FR039'', ''01FR039T2'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR039T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR039T1-full.png''}]','Freljord','Freljord',0,8,0,'Grant an ally +8|+4.INSERT INTO "API" VALUES (12,'[]','[''01PZ013T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ013.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ013-full.png''}]','Piltover & Zaun','PiltoverZaun',3,6,3,'<link=keyword.PlaySkillMark><sprite name=PlaySkillMark><style=Keyword>Play</style></link>: Discard your hand. Draw 3. Deal 3 to an enemy.','Play: Discard your hand. Draw 3. Deal 3 to an enemy.',NULL,NULL,'His dreams cost him his hands, yet he persisted. Nothing would stand in his way.','SIXMOREVODKA','Augmented Experimenter','01PZ013','[]','[]',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (13,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE019.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE019-full.png''}]','Demacia','Demacia',0,3,0,'Reduce the cost of all allies in hand by 1.','Reduce the cost of all allies in hand by 1.',NULL,NULL,'"From the fields to the front in a fortnight. This is what we expect from each and every able body in Demacia." - Garen','Kudos Productions','Mobilize','01DE019','[''Burst'']','[''Burst'']','Burst','Burst','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
