INSERT INTO "API" VALUES (17,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI038.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI038-full.png''}]','Shadow Isles','ShadowIsles',0,3,3,'When another ally dies, deal 1 to the enemy Nexus.','When another ally dies, deal 1 to the enemy Nexus.',NULL,NULL,'Her cruelest trick wasn''t slaughtering the soldiers who trusted the cries of a little girl, but sowing doubt in the survivors who returned home and ignored the pleas of their daughters.','SIXMOREVODKA','Phantom Prankster','01SI038','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (18,'[]','[''01DE042'', ''01DE042T2'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE042T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE042T1-full.png''}]','Demacia','Demacia',0,3,0,'Give an ally <link=keyword.Barrier><sprite name=Barrier><style=Keyword>Barrier</style></link> this round.INSERT INTO "API" VALUES (19,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ018.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ018-full.png''}]','Piltover & Zaun','PiltoverZaun',3,2,1,NULL,NULL,NULL,NULL,'How does she aim? That''s an excellent question.','SIXMOREVODKA','Academy Prodigy','01PZ018','[''Quick Attack'']','[''QuickStrike'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
