INSERT INTO "API" VALUES (21,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO008.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO008-full.png''}]','Ionia','Ionia',1,2,3,'When you <link=keyword.Stun><sprite name=Stunned><style=Keyword>Stun</style></link> or <link=keyword.Recall><style=Keyword>Recall</style></link> a unit, grant me +2|+0.','When you Stun or Recall a unit, grant me +2|+0.',NULL,NULL,'"Oh, so you think I''m ''cute''? ''Fuzzy''?? Let''s see how ''adorable'' you find THIS!"','SIXMOREVODKA','Fae Bladetwirler','01IO008','[''Quick Attack'']','[''QuickStrike'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (22,'[]','[''01NX032'', ''01NX048'', ''01NX005'', ''01NX030'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX048.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX048-full.png''}]','Noxus','Noxus',3,3,3,'When I survive damage, create a random Crimson unit in your hand.','When I survive damage, create a random Crimson unit in your hand.',NULL,NULL,'"Beloved companions!" "Were you? Well I received an invitation." "--Reveler''s Ball! Yes!" "Then we must! I shall present my family." "Starters before dessert, my dear. And you, Kye? Will you attend?"','SIXMOREVODKA','Crimson Curator','01NX048','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (23,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR006.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR006-full.png''}]','Freljord','Freljord',0,5,0,'Grant an ally and all allied copies of it <link=vocab.Everywhere><style=Vocab>everywhere</style></link> +2|+2.','Grant an ally and all allied copies of it everywhere +2|+2.',NULL,NULL,'"We few are Iceborn, our bloodlines infused with the Freljord''s magic. Our ancestors locked away an ancient evil, and now we few stand guard to defend against its return." - Gregor the Guardian','SIXMOREVODKA','Iceborn Legacy','01FR006','[''Slow'']','[''Slow'']','Slow','Slow','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (24,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR022.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR022-full.png''}]','Freljord','Freljord',1,1,1,'When I''m summoned, grant the top 2 allies in your deck +1|+1.','When I''m summoned, grant the top 2 allies in your deck +1|+1.',NULL,NULL,'"Three times our reavers reached Avarosan gates, and three time they were met with ready bows. What trickery warns them of our attacks?" - Scarthane Steffen','SIXMOREVODKA','Omen Hawk','01FR022','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (25,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR042.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR042-full.png''}]','Freljord','Freljord',0,6,0,'<link=keyword.Frostbite><sprite name=Frostbite><style=Keyword>Frostbite</style></link> 2 enemies. ','Frostbite 2 enemies. ',NULL,NULL,'"You''d challenge me on my own lands? You''re ill-prepared, little one." - Anivia','Kudos Productions','Harsh Winds','01FR042','[''Burst'']','[''Burst'']','Burst','Burst','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (26,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI049.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI049-full.png''}]','Shadow Isles','ShadowIsles',0,2,0,'Kill an ally to draw 2.','Kill an ally to draw 2.',NULL,NULL,'"I have erred. We were not meant to peer beyond the pale curtain. Whatever insight lingers there comes at far too great a cost." - Arie Wrence, Dauntless vindicator','Kudos Productions','Glimpse Beyond','01SI049','[''Fast'']','[''Fast'']','Fast','Fast','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
