INSERT INTO "API" VALUES (30,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE010.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE010-full.png''}]','Demacia','Demacia',5,5,4,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Create a random Elite in hand.','Last Breath: Create a random Elite in hand.',NULL,NULL,'"It takes a bold heart to trust their life to a silverwing, locked in combat far above solid ground. Bold, and highly durable." - Garen','SIXMOREVODKA','Swiftwing Lancer','01DE010','[''Last Breath'', ''Challenger'']','[''LastBreath'', ''Challenger'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (31,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI023.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI023-full.png''}]','Shadow Isles','ShadowIsles',2,2,3,'When you summon an <link=keyword.Ephemeral><sprite name=Ephemeral><style=Keyword>Ephemeral</style></link> ally, grant it +1|+1.','When you summon an Ephemeral ally, grant it +1|+1.',NULL,NULL,'Only the fallen knew that she did not walk alone. Only they could see the countless companions she led down the path to lands beyond.','SIXMOREVODKA','Soul Shepherd','01SI023','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (32,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ019.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ019-full.png''}]','Piltover & Zaun','PiltoverZaun',2,2,1,'When I''m summoned, refill 2 spell mana.','When I''m summoned, refill 2 spell mana.',NULL,NULL,'Not everyone is cut out to further progress in Piltover immediately. Some need a little guidance--those who look at invention through the wrong lens, for instance.','SIXMOREVODKA','Eager Apprentice','01PZ019','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (33,'[]','[''01NX038T2'', ''01NX038T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX038.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX038-full.png''}]','Noxus','Noxus',6,6,5,NULL,NULL,'I see the enemy Nexus has 10 or less Health.','I see the enemy Nexus has 10 or less Health.','"An iron will and a titan''s strength. There is no finer general to lead the Trifarian Legion." - Jericho Swain
INSERT INTO "API" VALUES (34,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO040.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO040-full.png''}]','Ionia','Ionia',2,4,2,NULL,NULL,NULL,NULL,'"Once, this place held our schools, our temples, our homes. Now, we are left to skulk about its shadow-infested ruins. Zed''s Order has defiled the legacy of this sacred place--I will be sure they regret it."','SIXMOREVODKA','Kinkou Lifeblade','01IO040','[''Lifesteal'', ''Elusive'']','[''Lifesteal'', ''Elusive'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (35,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR018.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR018-full.png''}]','Freljord','Freljord',3,3,2,'<link=vocab.Strike><style=Vocab>Strike</style></link>: If I struck a unit with 0 Power, kill it.','Strike: If I struck a unit with 0 Power, kill it.',NULL,NULL,'Predators of the northern reaches have learned that the easiest prey are those already crippled by winter''s bite.','SIXMOREVODKA','Rimefang Wolf','01FR018','[''Challenger'']','[''Challenger'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (36,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE020.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE020-full.png''}]','Demacia','Demacia',2,2,2,NULL,NULL,NULL,NULL,'"We didn''t know who or what those creatures were. But we knew the faces of our fellow soldiers by our sides, and that was all we needed."','SIXMOREVODKA','Vanguard Defender','01DE020','[''Tough'']','[''Tough'']',NULL,NULL,'COMMON','Common','ELITE','[''ELITE'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (37,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE034.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE034-full.png''}]','Demacia','Demacia',2,2,2,'When you summon an Elite, grant it +1|+1.','When you summon an Elite, grant it +1|+1.',NULL,NULL,'Wars are won in the forge.','SIXMOREVODKA','Battlesmith','01DE034','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (38,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE002.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE002-full.png''}]','Demacia','Demacia',7,8,7,'When I''m summoned, <link=vocab.Rally><style=Vocab>Rally</style></link>.','When I''m summoned, Rally.',NULL,NULL,'“Our House has bled for this realm. You’ll not throw away this family’s honor for a few tricks of light.”','SIXMOREVODKA','Tianna Crownguard','01DE002','[''Tough'']','[''Tough'']',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (39,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX023.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX023-full.png''}]','Noxus','Noxus',5,5,3,'When I''m summoned, grant other Spider allies +2|+0.','When I''m summoned, grant other Spider allies +2|+0.',NULL,NULL,'A single glance and you''re hers. A single bite and you''re theirs.','SIXMOREVODKA','Arachnoid Host','01NX023','[]','[]',NULL,NULL,'RARE','Rare','SPIDER','[''SPIDER'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (40,'[]','[''01IO041'', ''01IO041T2'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO041T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO041T1-full.png''}]','Ionia','Ionia',5,6,4,'When you play a spell, cast it again on the same targets.','When you play a spell, cast it again on the same targets.',NULL,NULL,'"We''ll bring peace to Ionia, whatever the cost."','SIXMOREVODKA','Karma','01IO041T1','[''Imbue'']','[''Imbue'']',NULL,NULL,'None','None',NULL,'[]','Champion','Unit',0,'Set1');
INSERT INTO "API" VALUES (41,'[]','[''01DE012'', ''01DE012T2'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE012T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE012T1-full.png''}]','Demacia','Demacia',6,5,6,'<link=vocab.RoundStart><style=Vocab>Round Start</style></link>: <link=vocab.Rally><style=Vocab>Rally</style></link>.','Round Start: Rally.',NULL,NULL,'"You think me rigid. Single-minded. Predictable. I am rigid, for nothing can sway me. I am single-minded, for I believe in Demacia. And I am predictable, for I will surely defeat you.”','SIXMOREVODKA','Garen','01DE012T1','[''Regeneration'']','[''Regeneration'']',NULL,NULL,'None','None','ELITE','[''ELITE'']','Champion','Unit',0,'Set1');
INSERT INTO "API" VALUES (42,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE017.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE017-full.png''}]','Demacia','Demacia',0,4,0,'If you have exactly 1 ally, grant it +3|+3.','If you have exactly 1 ally, grant it +3|+3.',NULL,NULL,'When others fail, it falls upon the shoulders of a true hero to find a path to victory.','Kudos Productions','Stand Alone','01DE017','[''Burst'']','[''Burst'']','Burst','Burst','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
