INSERT INTO "API" VALUES (44,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX013.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX013-full.png''}]','Noxus','Noxus',0,5,0,'<link=keyword.Stun><sprite name=Stunned><style=Keyword>Stun</style></link> an enemy. Give all allies +2|+0 this round.','Stun an enemy. Give all allies +2|+0 this round.',NULL,NULL,'"Any fool can throw overwhelming force at the enemy. It takes vision to conceal that force until the decisive moment." - Jericho Swain','Original Force','Decisive Maneuver','01NX013','[''Fast'']','[''Fast'']','Fast','Fast','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (45,'[]','[''01DE045T1'', ''01DE045T2'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE045.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE045-full.png''}]','Demacia','Demacia',3,3,3,NULL,NULL,'I''ve killed 2 enemies<style=Variable></style>.','I''ve killed 2 enemies.','"From arena to tournament, training ground to battleground, I long for a worthy opponent. I will not rest until I know I am the greatest."','SIXMOREVODKA','Fiora','01DE045','[''Challenger'']','[''Challenger'']',NULL,NULL,'Champion','Champion',NULL,'[]','Champion','Unit',1,'Set1');
