INSERT INTO "API" VALUES (47,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE052.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE052-full.png''}]','Demacia','Demacia',9,9,9,'<link=vocab.Play><style=Vocab>Play</style></link> or <link=vocab.Attack><style=Vocab>Attack</style></link>: Give all allies <link=keyword.Barrier><sprite name=Barrier><style=Keyword>Barrier</style></link> this round.','Play or Attack: Give all allies Barrier this round.',NULL,NULL,'"This formation is the basis of our tactics. It requires the faith of each soldier in their shield, and in the shields of their companions. So long as they stand, so too shall our realm." - Garen
INSERT INTO "API" VALUES (48,'[]','[''01PZ040T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ040T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ040T2-full.png''}]','Piltover & Zaun','PiltoverZaun',0,1,0,'Deal 4 to the enemy nexus and 1 to all enemies.','Deal 4 to the enemy nexus and 1 to all enemies.',NULL,NULL,'"See ya!" - Jinx','Ben Skutt','Super Mega Death Rocket!','01PZ040T2','[''Slow'', ''Fleeting'']','[''Slow'', ''Fleeting'']','Slow','Slow','None','None',NULL,'[]',NULL,'Spell',0,'Set1');
