INSERT INTO "API" VALUES (59,'[]','[''01IO009'', ''01IO009T3'', ''01IO009T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO009T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO009T2-full.png''}]','Ionia','Ionia',4,3,3,'<link=vocab.Attack><style=Vocab>Attack</style></link>: Summon an attacking <link=card.summon><style=AssociatedCard>Living Shadow</style></link> with my stats and keywords.','Attack: Summon an attacking Living Shadow with my stats and keywords.',NULL,NULL,'"Few men think to look back at their shadow. It is their last mistake."','SIXMOREVODKA','Zed','01IO009T2','[''Quick Attack'']','[''QuickStrike'']',NULL,NULL,'None','None',NULL,'[]','Champion','Unit',0,'Set1');
