INSERT INTO "API" VALUES (64,'[]','[''01DE022T1'', ''01DE022'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE022T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE022T2-full.png''}]','Demacia','Demacia',0,3,0,'<link=vocab.Rally><style=Vocab>Rally</style></link>.INSERT INTO "API" VALUES (65,'[]','[''01PZ032'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ028.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ028-full.png''}]','Piltover & Zaun','PiltoverZaun',0,1,0,'When cast or discarded, summon a <link=card.summon><style=AssociatedCard>Scrap Scuttler</style></link>.','When cast or discarded, summon a Scrap Scuttler.',NULL,NULL,'With a handful of scrap and mere moments left, the young inventor recalled an unusual source of inspiration: a creature she once saw scuttling along the rivers of a distant jungle.','Kudos Productions','Jury-Rig','01PZ028','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
