INSERT INTO "API" VALUES (91,'[]','[''01SI030T2'', ''01SI030T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI030.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI030-full.png''}]','Shadow Isles','ShadowIsles',4,3,3,NULL,NULL,'I''ve seen 3+ allies die<style=Variable></style>.','I''ve seen 3+ allies die.','In life, she was a general, a protector, a hero. But as flesh gave way, she was left with naught but the blazing fires of retribution--an undying spirit of vengeance.','SIXMOREVODKA','Kalista','01SI030','[''Fearsome'']','[''Fearsome'']',NULL,NULL,'Champion','Champion',NULL,'[]','Champion','Unit',1,'Set1');
