INSERT INTO "API" VALUES (97,'[]','[''01PZ030T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ030.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ030-full.png''}]','Piltover & Zaun','PiltoverZaun',1,4,3,'<link=keyword.PlaySkillMark><sprite name=PlaySkillMark><style=Keyword>Play</style></link>: Pick a follower. Transform me into an exact copy of it.','Play: Pick a follower. Transform me into an exact copy of it.',NULL,NULL,'"Hello, fellow Chem-Barons!"','SIXMOREVODKA','Shady Character','01PZ030','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
