INSERT INTO "API" VALUES (99,'[]','[''01PZ048T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ048.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ048-full.png''}]','Piltover & Zaun','PiltoverZaun',6,9,6,'<link=keyword.PlaySkillMark><sprite name=PlaySkillMark><style=Keyword>Play</style></link>: <link=keyword.Obliterate><style=Keyword>Obliterate</style></link> the top 5 cards of your deck to deal 1 to all enemies and the enemy Nexus for each spell obliterated.','Play: Obliterate the top 5 cards of your deck to deal 1 to all enemies and the enemy Nexus for each spell obliterated.',NULL,NULL,'"The narrow-minded Piltovans know only gears and metal, and cannot appreciate the delicate art in every stem, every petal, every cell of my cultivair. I will craft them an undeservedly graceful doom."','SIXMOREVODKA','Corina Veraza','01PZ048','[]','[]',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (100,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX030.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX030-full.png''}]','Noxus','Noxus',2,2,3,'When I survive damage, deal 1 to the enemy Nexus.','When I survive damage, deal 1 to the enemy Nexus.',NULL,NULL,'"Edvin! There you are, handsome. I was just thinking of you!" "Each of us can go, now…" "Escort me. I''ll make it fun." "Or nothing at all?"','SIXMOREVODKA','Crimson Disciple','01NX030','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
