INSERT INTO "API" VALUES (103,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX007.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX007-full.png''}]','Noxus','Noxus',2,2,2,'<link=vocab.Attack><style=Vocab>Attack</style></link>: Give other battling allies +1|+0 this round.','Attack: Give other battling allies +1|+0 this round.',NULL,NULL,'He roared with glee. For a moment, the heart of the arena pulsed in time with his and the excitement of the assembled masses was clutched in his triumphant hand.','SIXMOREVODKA','Arena Battlecaster','01NX007','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
