INSERT INTO "API" VALUES (105,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO026.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO026-full.png''}]','Ionia','Ionia',1,1,2,'<link=vocab.Play><style=Vocab>Play</style></link>: Grant an ally in hand +1|+0.','Play: Grant an ally in hand +1|+0.',NULL,NULL,'“Took years to cultivate this deadly physique! Tireless days of spotting birds, describing clouds, and lifting tray after tray of sweet buns! Who else has such dedication?”','SIXMOREVODKA','Inspiring Mentor','01IO026','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (106,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ013T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ013T1-full.png''}]','Piltover & Zaun','PiltoverZaun',0,0,0,'Discard your hand. Draw 3. Deal 3 to an enemy.','Discard your hand. Draw 3. Deal 3 to an enemy.',NULL,NULL,'Progress, whatever the price.','Rafael Zanchetin','Reckless Research','01PZ013T1','[''Skill'']','[''Skill'']',NULL,NULL,'None','None',NULL,'[]',NULL,'Ability',0,'Set1');
INSERT INTO "API" VALUES (107,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ002.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ002-full.png''}]','Piltover & Zaun','PiltoverZaun',3,4,2,'When I''m summoned, create in hand a card from your regions for each <link=card.me><style=AssociatedCard>Back Alley Barkeep</style></link> you''ve summoned this game. <style=Variable></style>','When I''m summoned, create in hand a card from your regions for each Back Alley Barkeep you''ve summoned this game. ',NULL,NULL,'"Yeah mate, it''s got a slight kick the same way the Sump''s got a slight smell. Bucket''s by the songspinner."','SIXMOREVODKA','Back Alley Barkeep','01PZ002','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (108,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI002.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI002-full.png''}]','Shadow Isles','ShadowIsles',1,1,1,NULL,NULL,NULL,NULL,'"What are you afraid of? It''s just ONE little spider." - Lord Sassen, Hapless Aristocrat','SIXMOREVODKA','Spiderling','01SI002','[]','[]',NULL,NULL,'None','None','SPIDER','[''SPIDER'']',NULL,'Unit',0,'Set1');
INSERT INTO "API" VALUES (109,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI005.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI005-full.png''}]','Shadow Isles','ShadowIsles',5,10,5,'Reduce my cost by 1 for each ally that died this game.','Reduce my cost by 1 for each ally that died this game.',NULL,NULL,'Once a beast of burden for a kingdom long forgotten, this monster now scavenges across forgotten battlefields, adding scrap to its shell, and the souls of the dead to its core.','SIXMOREVODKA','Scuttlegeist','01SI005','[''Fearsome'']','[''Fearsome'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (110,'[]','[''01FR038T2'', ''01FR038T1'', ''01FR038T3'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR038.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR038-full.png''}]','Freljord','Freljord',5,4,3,'<link=vocab.Attack><style=Vocab>Attack</style></link>: <link=keyword.Frostbite><sprite name=Frostbite><style=Keyword>Frostbite</style></link> the <link=vocab.Strongest><style=Vocab>Strongest</style></link> enemy.','Attack: Frostbite the Strongest enemy.','You <link=keyword.Frostbite><sprite name=Frostbite><style=Keyword>Frostbite</style></link> 5+ enemies<style=Variable></style>. When I level up, create a <link=card.create><style=AssociatedCard>Crystal Arrow</style></link> on top of deck.','You Frostbite 5+ enemies. When I level up, create a Crystal Arrow on top of deck.','"When I look out over my home, I see what it is, but also what it could be. Prosperous and plentiful, not only for my people, but for all those who seek peace. The Freljord, united."','SIXMOREVODKA','Ashe','01FR038','[]','[]',NULL,NULL,'Champion','Champion',NULL,'[]','Champion','Unit',1,'Set1');
INSERT INTO "API" VALUES (111,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE055.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE055-full.png''}]','Demacia','Demacia',4,3,2,'<link=vocab.Play><style=Vocab>Play</style></link>: Give an ally <link=keyword.Challenger><sprite name=Challenger><style=Keyword>Challenger</style></link> this round.','Play: Give an ally Challenger this round.',NULL,NULL,'"He seemed a preening fop with an expensive blade--turns out he really knew how to swing that sword! I''d demand a rematch, but I missed his name with that ridiculous accent." - Demacian Ensign','JiHun Lee','Laurent Duelist','01DE055','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (112,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ004.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ004-full.png''}]','Piltover & Zaun','PiltoverZaun',0,7,0,'Deal 3 to an enemy or the enemy Nexus, 2 to another, and 1 to another.','Deal 3 to an enemy or the enemy Nexus, 2 to another, and 1 to another.',NULL,NULL,'"When you''ve got talent, there''s no such thing as a lucky shot." - Ezreal','Max Grecke','Trueshot Barrage','01PZ004','[''Slow'']','[''Slow'']','Slow','Slow','EPIC','Epic',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (113,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE048.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE048-full.png''}]','Demacia','Demacia',4,4,3,'Grant me +2|+2 once you''ve cast a 6+ cost spell this game.','Grant me +2|+2 once you''ve cast a 6+ cost spell this game.',NULL,NULL,'"Long ago, the wild magicks of the Rune Wars brought all Runeterra to its knees. Thus, our order was created to protect our kingdom by ridding it of magic, whether abroad or within." - Mageseeker''s Handbook','SIXMOREVODKA','Mageseeker Inciter','01DE048','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (114,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T9.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T9-full.png''}]','Piltover & Zaun','PiltoverZaun',4,4,1,NULL,NULL,NULL,NULL,'"PROGRESS CONTINUES! I have finally found a way to combine the raw power of hexenergy with my ball tosser! I present, the STORMLOBBER! Now to sleep."
INSERT INTO "API" VALUES (115,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO024.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO024-full.png''}]','Ionia','Ionia',0,6,0,'Summon 2 exact copies of an ally. They''re <link=keyword.Ephemeral><sprite name=Ephemeral><style=Keyword>Ephemeral</style></link>.','Summon 2 exact copies of an ally. They''re Ephemeral.',NULL,NULL,'"Shen is one man caught between the perils of two worlds, he will fail them both. I devote myself to Ionia alone." - Zed','Kudos Productions','Dawn and Dusk','01IO024','[''Slow'']','[''Slow'']','Slow','Slow','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (116,'[]','[''01SI053T1'', ''01SI053'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI053T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI053T2-full.png''}]','Shadow Isles','ShadowIsles',4,2,3,'Other Spider allies have <link=keyword.Challenger><sprite name=Challenger><style=Keyword>Challenger</style></link> and <link=keyword.Fearsome><sprite name=Fearsome><style=Keyword>Fearsome</style></link>.','Other Spider allies have Challenger and Fearsome.',NULL,NULL,'Beauty is in the many eyes of the beholder.','SIXMOREVODKA','Spider Queen Elise','01SI053T2','[''Fearsome'', ''Challenger'']','[''Fearsome'', ''Challenger'']',NULL,NULL,'None','None','SPIDER','[''SPIDER'']','Champion','Unit',0,'Set1');
INSERT INTO "API" VALUES (117,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE001.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE001-full.png''}]','Demacia','Demacia',3,4,3,'<link=vocab.Allegiance><style=Vocab>Allegiance</style></link>: Grant other allies +1|+1.','Allegiance: Grant other allies +1|+1.',NULL,NULL,'"You must understand the weight of our banner. It flies for our king, our houses, our citizens. It is our unwavering belief in Demacia itself. Hold it high. Show them our pride." - Tianna Crownguard ','SIXMOREVODKA','Vanguard Bannerman','01DE001','[]','[]',NULL,NULL,'RARE','Rare','ELITE','[''ELITE'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (118,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ020.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ020-full.png''}]','Piltover & Zaun','PiltoverZaun',1,1,1,NULL,NULL,NULL,NULL,'Her first launch was pure accident: she slipped inside a Progress Day cannon while preening herself. Now she''s the toast of Piltover, arcing across the sky to the adoring gasps of the crowds below.','SIXMOREVODKA','Daring Poro','01PZ020','[''Elusive'']','[''Elusive'']',NULL,NULL,'COMMON','Common','PORO','[''PORO'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (119,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX021.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX021-full.png''}]','Noxus','Noxus',3,3,2,'<link=vocab.Attack><style=Vocab>Attack</style></link>: Grant allied Legion Marauders <link=vocab.Everywhere><style=Vocab>everywhere</style></link> +1|+1.','Attack: Grant allied Legion Marauders everywhere +1|+1.',NULL,NULL,'The Trifarian Legion is trailed by opportunistic brigands who prey on the weak and injured in its wake.','SIXMOREVODKA','Legion Marauder','01NX021','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
