INSERT INTO "API" VALUES (121,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ046.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ046-full.png''}]','Piltover & Zaun','PiltoverZaun',0,1,0,'Pick a card in hand. Shuffle 4 exact copies of it into your deck.','Pick a card in hand. Shuffle 4 exact copies of it into your deck.',NULL,NULL,'Imitation is the sincerest form of thievery.','Kudos Productions','Counterfeit Copies','01PZ046','[''Burst'']','[''Burst'']','Burst','Burst','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
