INSERT INTO "API" VALUES (142,'[]','[''01DE022'', ''01DE022T2'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE022T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE022T1-full.png''}]','Demacia','Demacia',4,2,3,'Each round, the first time an ally dies, <link=vocab.Rally><style=Vocab>Rally</style></link>.','Each round, the first time an ally dies, Rally.',NULL,NULL,'"World''s full of monsters. If you''re lucky, they''re the ones you can see. The worst are the ones that stay under your skin."','SIXMOREVODKA','Lucian','01DE022T1','[''Double Attack'']','[''DoubleStrike'']',NULL,NULL,'None','None',NULL,'[]','Champion','Unit',0,'Set1');
