INSERT INTO "API" VALUES (147,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI003.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI003-full.png''}]','Shadow Isles','ShadowIsles',0,9,0,'Revive the 6 <link=vocab.Strongest><style=Vocab>Strongest</style></link> allies that died this game and grant them <link=keyword.Ephemeral><sprite name=Ephemeral><style=Keyword>Ephemeral</style></link>.','Revive the 6 Strongest allies that died this game and grant them Ephemeral.',NULL,NULL,'On certain nights, a tide of hungry spirits swells the Black Mist. It carries them across the seas to prey on the living, and feed the growing darkness with foul new unlife.','Rafael Zanchetin','The Harrowing','01SI003','[''Slow'']','[''Slow'']','Slow','Slow','EPIC','Epic',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (148,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI041.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI041-full.png''}]','Shadow Isles','ShadowIsles',2,3,2,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Revive me at the next <link=vocab.RoundStart><style=Vocab>Round Start</style></link> and grant me +1|+1 for each time I''ve died. <style=Variable></style>','Last Breath: Revive me at the next Round Start and grant me +1|+1 for each time I''ve died. ',NULL,NULL,'The old martyr remembered rallying his comrades to their doom. But it had been years since he could remember why...','SIXMOREVODKA','The Undying','01SI041','["Can''t Block", ''Last Breath'']','[''CantBlock'', ''LastBreath'']',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
