INSERT INTO "API" VALUES (150,'[]','[''01FR049T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR049.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR049-full.png''}]','Freljord','Freljord',3,2,2,'When I''m summoned, the enemy summons a <link=card.summon><style=AssociatedCard>Snow Hare</style></link>.','When I''m summoned, the enemy summons a Snow Hare.',NULL,NULL,'"You cannot make a wolf from a hare." - Winter''s Claw proverb','SIXMOREVODKA','Stalking Wolf','01FR049','[''Challenger'']','[''Challenger'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (151,'[]','[''01IO032'', ''01IO032T2'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO032T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO032T1-full.png''}]','Ionia','Ionia',4,4,6,'<link=vocab.Support><style=Vocab>Support</style></link>: Give my supported ally <link=keyword.Barrier><sprite name=Barrier><style=Keyword>Barrier</style></link> this round.INSERT INTO "API" VALUES (152,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE053.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE053-full.png''}]','Demacia','Demacia',3,4,2,'<link=vocab.Strike><style=Vocab>Strike</style></link>: Create in hand another <link=keyword.Challenger><sprite name=Challenger><style=Keyword>Challenger</style></link> follower from your regions.','Strike: Create in hand another Challenger follower from your regions.',NULL,NULL,'"...Good grief." - Fiora','SIXMOREVODKA','Laurent Chevalier','01DE053','[''Challenger'']','[''Challenger'']',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (153,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI045.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI045-full.png''}]','Shadow Isles','ShadowIsles',0,1,0,'<link=keyword.Drain><style=Keyword>Drain</style></link> 4 from an ally.','Drain 4 from an ally.',NULL,NULL,'"What kills you only makes me stronger." - Thresh','Kudos Productions','Absorb Soul','01SI045','[''Fast'']','[''Fast'']','Fast','Fast','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (154,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR037.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR037-full.png''}]','Freljord','Freljord',3,4,3,'<link=vocab.Allegiance><style=Vocab>Allegiance</style></link>: Grant the top ally in your deck +3|+3 and <link=keyword.Overwhelm><sprite name=Overwhelm><style=Keyword>Overwhelm</style></link>.','Allegiance: Grant the top ally in your deck +3|+3 and Overwhelm.',NULL,NULL,'As the rows of reinforcements crested the ridge, the Outriders bowed their heads to the warmother. For with her--their Avarosa in the flesh, their queen Ashe--came the promise of peace.','SIXMOREVODKA','Avarosan Outriders','01FR037','[''Overwhelm'']','[''Overwhelm'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (155,'[]','[''01SI002'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI036.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI036-full.png''}]','Shadow Isles','ShadowIsles',0,1,0,'If an ally died this round, summon 2 <link=card.create><style=AssociatedCard>Spiderlings</style></link>.','If an ally died this round, summon 2 Spiderlings.',NULL,NULL,'That creeping feeling on your skin isn''t nearly as unsettling as the one underneath it.','Kudos Productions','Crawling Sensation','01SI036','[''Slow'']','[''Slow'']','Slow','Slow','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (156,'[]','[''01FR009T2'', ''01FR009'', ''01FR053'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR009T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR009T1-full.png''}]','Freljord','Freljord',1,4,6,'When I survive damage, summon a <link=card.create><style=AssociatedCard>Mighty Poro</style></link>.','When I survive damage, summon a Mighty Poro.',NULL,NULL,'"Listen closely, ''n I''ll tell you about Braum and the mightiest of his poros!" - Ingvar the Elder','SIXMOREVODKA','Braum','01FR009T1','[''Challenger'', ''Regeneration'']','[''Challenger'', ''Regeneration'']',NULL,NULL,'None','None',NULL,'[]','Champion','Unit',0,'Set1');
INSERT INTO "API" VALUES (157,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO013.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO013-full.png''}]','Ionia','Ionia',4,1,3,NULL,NULL,NULL,NULL,'"What would you sacrifice for power? Your path begins with an oath, and ends only when it has taken all you have to give." - Zed','SIXMOREVODKA','Shadow Fiend','01IO013','[''Ephemeral'']','[''Ephemeral'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (158,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ031.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ031-full.png''}]','Piltover & Zaun','PiltoverZaun',0,4,0,'Deal 1 to an enemy or the enemy Nexus, and 1 to another.INSERT INTO "API" VALUES (159,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI024.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI024-full.png''}]','Shadow Isles','ShadowIsles',2,2,2,NULL,NULL,NULL,NULL,'No longer bound by flesh, rider and beast became one, determined to race mindlessly into battles they no longer understood.','SIXMOREVODKA','Spectral Rider','01SI024','[''Ephemeral'']','[''Ephemeral'']',NULL,NULL,'None','None',NULL,'[]',NULL,'Unit',0,'Set1');
INSERT INTO "API" VALUES (160,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI051.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI051-full.png''}]','Shadow Isles','ShadowIsles',4,5,4,'When an ally dies, refill your spell mana.','When an ally dies, refill your spell mana.',NULL,NULL,'He toiled night and day, perfecting his composition. Then, in the blink of an eye, a dark silence blew through him. Others screamed and ran for their lives. He noticed nothing.','SIXMOREVODKA','Tortured Prodigy','01SI051','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (161,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR026.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR026-full.png''}]','Freljord','Freljord',7,6,6,NULL,NULL,NULL,NULL,'The power of a warhorse, the thoughtless savagery of a cat.','SIXMOREVODKA','Alpha Wildclaw','01FR026','[''Overwhelm'']','[''Overwhelm'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (162,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX054.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX054-full.png''}]','Noxus','Noxus',0,5,0,'<link=keyword.Stun><sprite name=Stunned><style=Keyword>Stun</style></link> all enemies with 4 or less Power.','Stun all enemies with 4 or less Power.',NULL,NULL,'“He’s taking a deep breath - we might get a - yes, there we have it, folks! That’s Thunder’s famous war cry! We’re all shaking in our boots out here, Thuuuunder!” - Arena Battlecaster','Kudos Productions','Intimidating Roar','01NX054','[''Slow'']','[''Slow'']','Slow','Slow','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (163,'[]','[''01NX006'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX006T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX006T2-full.png''}]','Noxus','Noxus',0,0,0,'For each attacking ally other than <link=card.vlad><style=AssociatedCard>Vladimir</style></link>, deal 1 to it and 1 to the enemy Nexus.','For each attacking ally other than Vladimir, deal 1 to it and 1 to the enemy Nexus.',NULL,NULL,'"Delicious." - Vladimir','Max Grecke','Crimson Pact','01NX006T2','[''Skill'']','[''Skill'']',NULL,NULL,'None','None',NULL,'[]',NULL,'Ability',0,'Set1');
