INSERT INTO "API" VALUES (169,'[]','[''01SI052'', ''01SI052T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI052T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI052T2-full.png''}]','Shadow Isles','ShadowIsles',0,4,0,'Deal 3 to each enemy that was summoned this round.INSERT INTO "API" VALUES (170,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ001.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ001-full.png''}]','Piltover & Zaun','PiltoverZaun',0,1,0,'Discard 2 to draw 2.INSERT INTO "API" VALUES (171,'[]','[''01NX042'', ''01NX042T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX042T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX042T2-full.png''}]','Noxus','Noxus',4,4,3,'<link=vocab.Play><style=Vocab>Play</style></link>: <link=vocab.Rally><style=Vocab>Rally</style></link>.INSERT INTO "API" VALUES (172,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR013.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR013-full.png''}]','Freljord','Freljord',3,6,8,'When I survive damage, grant me +3|+0.','When I survive damage, grant me +3|+0.',NULL,NULL,'"I would die shivering in the cold before sharing a hearth with Ashe''s weaklings. But if they desire warmth, I will give it to them.”','SIXMOREVODKA','Scarmother Vrynna','01FR013','[''Overwhelm'']','[''Overwhelm'']',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (173,'[]','[''01PZ032'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ057.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ057-full.png''}]','Piltover & Zaun','PiltoverZaun',0,2,0,'Summon 2 <link=card.summon><style=AssociatedCard>Scrap Scuttlers</style></link>.','Summon 2 Scrap Scuttlers.',NULL,NULL,'Two gentle creatures, once separated by an impassable lane of land, were finally brought together in the tepid waters of the Sump.','Kudos Productions','Scrapdash Assembly','01PZ057','[''Slow'']','[''Slow'']','Slow','Slow','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (174,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI031.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI031-full.png''}]','Shadow Isles','ShadowIsles',2,3,4,'<link=vocab.Attack><style=Vocab>Attack</style></link>: Grant me +1|+0 for each <link=keyword.Ephemeral><sprite name=Ephemeral><style=Keyword>Ephemeral</style></link> ally you have.','Attack: Grant me +1|+0 for each Ephemeral ally you have.',NULL,NULL,'In death, as in life, he bellows the twisted, dark command. And in death, as in life, Hecarim''s loyal knights answer, charging forth to slaughter.','SIXMOREVODKA','Iron Harbinger','01SI031','[''Fearsome'']','[''Fearsome'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (175,'[]','[''01NX038T2'', ''01NX038'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX038T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX038T1-full.png''}]','Noxus','Noxus',0,5,0,'Deal 4 to the enemy Nexus.INSERT INTO "API" VALUES (176,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI034.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI034-full.png''}]','Shadow Isles','ShadowIsles',0,3,0,'If an ally died this round, deal 3 to a unit.','If an ally died this round, deal 3 to a unit.',NULL,NULL,'"Our spear sings for the fallen." - Kalista','Wild Blue Studios','Black Spear','01SI034','[''Fast'']','[''Fast'']','Fast','Fast','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (177,'[]','[''01SI002'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI043.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI043-full.png''}]','Shadow Isles','ShadowIsles',1,1,1,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Summon a <link=card.summon><style=AssociatedCard>Spiderling</style></link>.','Last Breath: Summon a Spiderling.',NULL,NULL,'"L-Lady Elise? Where... where did you go?"','SIXMOREVODKA','Hapless Aristocrat','01SI043','[''Last Breath'']','[''LastBreath'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (178,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO018.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO018-full.png''}]','Ionia','Ionia',0,1,0,'Give an ally +1|+0 and <link=keyword.Quick Strike><sprite name=QuickStrike><style=Keyword>Quick Attack</style></link> this round.','Give an ally +1|+0 and Quick Attack this round.',NULL,NULL,'Combat is merely a race to take the life of another before they take yours.','Kudos Productions','Rush','01IO018','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (179,'[]','[''01PZ056'', ''01PZ056T10'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T3.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T3-full.png''}]','Piltover & Zaun','PiltoverZaun',0,8,0,'Draw 3, then reduce those cards'' costs by 1.INSERT INTO "API" VALUES (180,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR019.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR019-full.png''}]','Freljord','Freljord',0,7,0,'Kill all enemies with 0 Power, then <link=keyword.Frostbite><sprite name=Frostbite><style=Keyword>Frostbite</style></link> all enemies.','Kill all enemies with 0 Power, then Frostbite all enemies.',NULL,NULL,'Warmother Winter is the first and last foe faced by any who would invade the Freljord. Her bloodsworn are the merciless wind and the biting frost.','SIXMOREVODKA','Winter''s Breath','01FR019','[''Slow'']','[''Slow'']','Slow','Slow','EPIC','Epic',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (181,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE033.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE033-full.png''}]','Demacia','Demacia',0,6,0,'Costs 1 less for each ally that died this round. Summon a random 5 cost follower from Demacia.','Costs 1 less for each ally that died this round. Summon a random 5 cost follower from Demacia.',NULL,NULL,'"Today we rise to right the injustices that felled those before us. The sacrifices of our comrades were not in vain." - Radiant Guardian','Original Force','Remembrance','01DE033','[''Slow'']','[''Slow'']','Slow','Slow','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (182,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI009.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI009-full.png''}]','Shadow Isles','ShadowIsles',3,2,2,'<link=vocab.Support><style=Vocab>Support</style></link>: Grant my supported ally +2|+0 and <link=keyword.Ephemeral><sprite name=Ephemeral><style=Keyword>Ephemeral</style></link>.','Support: Grant my supported ally +2|+0 and Ephemeral.',NULL,NULL,'Some look at the Ruination and only see the destruction and misery. Others see the glass half full.','SIXMOREVODKA','Stirred Spirits','01SI009','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (183,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ027.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ027-full.png''}]','Piltover & Zaun','PiltoverZaun',0,0,0,'To play, spend all your mana.INSERT INTO "API" VALUES (184,'[]','[''01DE045T2'', ''01DE045'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE045T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE045T1-full.png''}]','Demacia','Demacia',4,3,4,'When I''ve killed 4 enemies and survived, you win the game. <style=Variable></style>','When I''ve killed 4 enemies and survived, you win the game. ',NULL,NULL,'"... and now I know."','SIXMOREVODKA','Fiora','01DE045T1','[''Challenger'']','[''Challenger'']',NULL,NULL,'None','None',NULL,'[]','Champion','Unit',0,'Set1');
INSERT INTO "API" VALUES (185,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR041.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR041-full.png''}]','Freljord','Freljord',5,5,5,'When I''m summoned, grant all allies in your deck +1|+1.','When I''m summoned, grant all allies in your deck +1|+1.',NULL,NULL,'"Many tribes under one banner! Perhaps one day all the Freljord will fight side by side."','SIXMOREVODKA','Avarosan Hearthguard ','01FR041','[]','[]',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (186,'[]','[''01NX002'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX051.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX051-full.png''}]','Noxus','Noxus',8,8,8,'When I''m summoned, create 3 <link=card.create><style=AssociatedCard>Decimates</style></link> in hand.','When I''m summoned, create 3 Decimates in hand.',NULL,NULL,'Deep in Zaun''s Sump, young Benn Farron was labeled a menace. Unstable. Unacceptable. In the ranks of Noxus he was embraced. Awarded. Unstoppable.','SIXMOREVODKA','Captain Farron','01NX051','[''Overwhelm'']','[''Overwhelm'']',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (187,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR025.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR025-full.png''}]','Freljord','Freljord',2,2,3,'When I''m summoned, draw a Poro if you have a Poro ally.','When I''m summoned, draw a Poro if you have a Poro ally.',NULL,NULL,'A herd needs just two things: love, and company. Anything else is just fluff.
INSERT INTO "API" VALUES (188,'[]','[''01DE042'', ''01DE042T1'', ''01DE042T3'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE042T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE042T2-full.png''}]','Demacia','Demacia',5,6,6,'When you cast 6+ mana of spells, create a <link=card.warcry><style=AssociatedCard>Final Spark</style></link> in hand. <style=Variable></style>','When you cast 6+ mana of spells, create a Final Spark in hand. ',NULL,NULL,'"No more holding back!"','SIXMOREVODKA','Lux','01DE042T2','[''Barrier'']','[''Barrier'']',NULL,NULL,'None','None',NULL,'[]','Champion','Unit',0,'Set1');
INSERT INTO "API" VALUES (189,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE044.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE044-full.png''}]','Demacia','Demacia',0,6,0,'Fully heal an ally, then double its Power and Health.','Fully heal an ally, then double its Power and Health.',NULL,NULL,'In Demacia, to be as good as two of the enemy isn''t just a boast.','Rafael Zanchetin','Redoubled Valor','01DE044','[''Slow'']','[''Slow'']','Slow','Slow','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (190,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T8.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T8-full.png''}]','Piltover & Zaun','PiltoverZaun',3,3,1,NULL,NULL,NULL,NULL,'"Ah, the sweet smell of science! I have successfully upgraded my turrets! I must say... this model''s appearance sends hypothermic waves through my vertebrae! Brr!"
INSERT INTO "API" VALUES (191,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX012.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX012-full.png''}]','Noxus','Noxus',3,1,1,NULL,NULL,NULL,NULL,'In Noxus, where soldiers are revered for their audacity on the battlefield, rearguard duty is nothing short of a punishment.','SIXMOREVODKA','Legion Rearguard','01NX012','["Can''t Block"]','[''CantBlock'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (192,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE024.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE024-full.png''}]','Demacia','Demacia',1,1,1,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Create in hand a 6+ cost spell from a region other than Demacia.','Last Breath: Create in hand a 6+ cost spell from a region other than Demacia.',NULL,NULL,'"Arcane items have undeniable intrigue. But these objects of power are best left to the capable hands of our experts, and away from the well-meaning ignorance of our citizens." - Mageseeker''s Handbook','SIXMOREVODKA','Mageseeker Conservator','01DE024','[''Last Breath'']','[''LastBreath'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (193,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI007T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI007T1-full.png''}]','Shadow Isles','ShadowIsles',1,1,1,NULL,NULL,NULL,NULL,'...each spirit another victim of the relic''s allure. They seethe in silence as they await the arrival of the next greedy fool.','SIXMOREVODKA','Unleashed Spirit','01SI007T1','[''Ephemeral'']','[''Ephemeral'']',NULL,NULL,'None','None',NULL,'[]',NULL,'Unit',0,'Set1');
INSERT INTO "API" VALUES (194,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX043.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX043-full.png''}]','Noxus','Noxus',0,1,0,'Deal 1 to anything.','Deal 1 to anything.',NULL,NULL,'"In the right hands, a blade can cut through anything... and I do mean anything." - Katarina','SIXMOREVODKA','Blade''s Edge','01NX043','[''Fast'']','[''Fast'']','Fast','Fast','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (195,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO056T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO056T1-full.png''}]','Ionia','Ionia',0,0,0,'<link=keyword.Stun><sprite name=Stunned><style=Keyword>Stun</style></link> 2 enemies.','Stun 2 enemies.',NULL,NULL,'"Stand aside. I have come for the Unforgiven." - Yone, Windchaser','Kudos Productions','Staggering Strikes','01IO056T1','[''Skill'']','[''Skill'']',NULL,NULL,'None','None',NULL,'[]',NULL,'Ability',0,'Set1');
INSERT INTO "API" VALUES (196,'[]','[''01SI030T2'', ''01SI030'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI030T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI030T1-full.png''}]','Shadow Isles','ShadowIsles',0,3,0,'If an ally died this round, deal 3 to a unit.INSERT INTO "API" VALUES (197,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX037.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX037-full.png''}]','Noxus','Noxus',3,2,2,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Deal 1 to the enemy Nexus.','Last Breath: Deal 1 to the enemy Nexus.',NULL,NULL,'Every Noxian is taught that a life spent in service to the empire is well spent, but few spend their lives as spectacularly as the Legion''s grenadiers.','SIXMOREVODKA','Legion Grenadier','01NX037','[''Last Breath'']','[''LastBreath'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (198,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO016.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO016-full.png''}]','Ionia','Ionia',4,6,4,'<link=vocab.Play><style=Vocab>Play</style></link>: Create an exact copy of a card in hand.','Play: Create an exact copy of a card in hand.',NULL,NULL,'"As the warrior wept for his loss, the elder consoled him: ''Seek the sage of the skies. Only he can return that which is lost to this world, but still held in memory.''" - Saga of the First Lands','SIXMOREVODKA','Zephyr Sage','01IO016','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (199,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI056.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI056-full.png''}]','Shadow Isles','ShadowIsles',3,3,2,'When I''m summoned, give other Spider allies +1|+0 and enemies <nobr>-1|-0</nobr> this round.','When I''m summoned, give other Spider allies +1|+0 and enemies -1|-0 this round.',NULL,NULL,'"They can spin a web the size of a man in less than a minute... would you like a demonstration?" - Elise','SIXMOREVODKA','Frenzied Skitterer','01SI056','[''Fearsome'']','[''Fearsome'']',NULL,NULL,'RARE','Rare','SPIDER','[''SPIDER'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (200,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX010.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX010-full.png''}]','Noxus','Noxus',4,5,4,'When I''m summoned, grant me +1|+1 for each unit you''ve <link=keyword.Stun><sprite name=Stunned><style=Keyword>Stunned</style></link> or <link=keyword.Recall><style=Keyword>Recalled</style></link> this game. <style=Variable></style>','When I''m summoned, grant me +1|+1 for each unit you''ve Stunned or Recalled this game. ',NULL,NULL,'All Noxians know the three Principles of Strength, but if a soldier is to rise through the ranks, they must learn to master them.','SIXMOREVODKA','Legion General','01NX010','[''Fearsome'']','[''Fearsome'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (201,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX017.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX017-full.png''}]','Noxus','Noxus',3,2,2,'<link=vocab.Support><style=Vocab>Support</style></link>: Give my supported ally <link=keyword.Quick Strike><sprite name=QuickStrike><style=Keyword>Quick Attack</style></link> this round.','Support: Give my supported ally Quick Attack this round.',NULL,NULL,'The Legion spread the empire''s reach with every beat of her drum. Nothing could stop them. Nothing did.','SIXMOREVODKA','Legion Drummer','01NX017','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (202,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE004.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE004-full.png''}]','Demacia','Demacia',2,4,1,'When I''m summoned, summon an exact copy of me.','When I''m summoned, summon an exact copy of me.',NULL,NULL,'They fell from the clouds like silvery bolts of lightning, swift and sure as they dove toward their targets. Then, as suddenly as they appeared, they were gone. ','SIXMOREVODKA','Silverwing Vanguard','01DE004','[''Challenger'']','[''Challenger'']',NULL,NULL,'COMMON','Common','ELITE','[''ELITE'']',NULL,'Unit',1,'Set1');
