INSERT INTO "API" VALUES (207,'[]','[''01PZ022'', ''01PZ008T2'', ''01PZ008T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ008.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ008-full.png''}]','Piltover & Zaun','PiltoverZaun',1,1,1,'<link=vocab.Nexus Strike><style=Vocab>Nexus Strike</style></link>: Plant 5 <link=card.shuffle><style=AssociatedCard>Poison Puffcaps</style></link> on random cards in the enemy deck.','Nexus Strike: Plant 5 Poison Puffcaps on random cards in the enemy deck.','You''ve planted 15+ <link=card.shuffle><style=AssociatedCard>Poison Puffcaps</style></link><style=Variable></style>.','You''ve planted 15+ Poison Puffcaps.','"Bandle Scout Rule 154: Never fear the unknown! Rule 276: Denizens of the woodlands are our friends! Rule 354: If it''s fuzzy, it might be safe to pet but certainly isn''t safe to eat! Rule 417..."','SIXMOREVODKA','Teemo','01PZ008','[''Elusive'']','[''Elusive'']',NULL,NULL,'Champion','Champion',NULL,'[]','Champion','Unit',1,'Set1');
