INSERT INTO "API" VALUES (236,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR052T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR052T1-full.png''}]','Freljord','Freljord',0,0,0,'<link=keyword.Obliterate><style=Keyword>Obliterate</style></link> ALL followers with 4 or less Power in play and in hands.','Obliterate ALL followers with 4 or less Power in play and in hands.',NULL,NULL,'“Unearthly light flooded the valley as a piercing wail rattled the rocks from the cliffs, my sinews from their bones, the very thoughts from my mind! Then... silence.” - Bjerg the Wanderer','Max Grecke','Balesight','01FR052T1','[''Skill'']','[''Skill'']',NULL,NULL,'None','None',NULL,'[]',NULL,'Ability',0,'Set1');
INSERT INTO "API" VALUES (237,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE040.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE040-full.png''}]','Demacia','Demacia',3,2,2,'Grant me +1|+1 and <link=keyword.Challenger><sprite name=Challenger><style=Keyword>Challenger</style></link> once you''ve cast a 6+ cost spell this game.','Grant me +1|+1 and Challenger once you''ve cast a 6+ cost spell this game.',NULL,NULL,'"Citizens of Demacia, it is my honor to keep you safe. But we must demand your unwavering support, for even within our high walls, mages still walk among us!"
INSERT INTO "API" VALUES (238,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX036.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX036-full.png''}]','Noxus','Noxus',6,6,6,'<link=vocab.RoundStart><style=Vocab>Round Start</style></link>: <link=keyword.Stun><sprite name=Stunned><style=Keyword>Stun</style></link> the <link=keyword.Weakest><style=Keyword>Weakest</style></link> enemy.','Round Start: Stun the Weakest enemy.',NULL,NULL,'"I don''t care who wronged you or what they did. You need me to make it right in the pit, you pay up front. There''s no discount for sad stories."','SIXMOREVODKA','Minotaur Reckoner','01NX036','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (239,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX044.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX044-full.png''}]','Noxus','Noxus',0,6,12,'<link=vocab.Attack><style=Vocab>Attack</style></link>: Grant me +4|+0.','Attack: Grant me +4|+0.',NULL,NULL,'"Sir, they''re refusing to open their gates. They''ve demanded to speak with Darius, but he''s two days'' ride away. Should we send riders?"
