INSERT INTO "API" VALUES (269,'[]','[''01IO041T2'', ''01IO041T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO041.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO041-full.png''}]','Ionia','Ionia',4,6,3,'<link=vocab.RoundEnd><style=Vocab>Round End</style></link>: Create in hand a spell from your regions.','Round End: Create in hand a spell from your regions.','You''re <link=keyword.Enlightened><style=Keyword>Enlightened</style></link>.','You''re Enlightened.','"Through reflection, we can focus the mind, and find a path around any obstacle."','SIXMOREVODKA','Karma','01IO041','[]','[]',NULL,NULL,'Champion','Champion',NULL,'[]','Champion','Unit',1,'Set1');
INSERT INTO "API" VALUES (270,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI006.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI006-full.png''}]','Shadow Isles','ShadowIsles',0,5,0,'Steal an enemy follower this round. <style=Parentheses>(Can''t play if you have 6 allies already.)</style>','Steal an enemy follower this round. (Can''t play if you have 6 allies already.)',NULL,NULL,'He woke to find his hands glistening red and the camp unusually quiet. ','Kudos Productions','Possession','01SI006','[''Slow'']','[''Slow'']','Slow','Slow','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (271,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE015.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE015-full.png''}]','Demacia','Demacia',5,5,5,'When I''m summoned, grant me <link=keyword.Lifesteal><sprite name=Lifesteal><style=Keyword>Lifesteal</style></link> and <link=keyword.Tough><sprite name=Tough><style=Keyword>Tough</style></link> if an ally died this round.','When I''m summoned, grant me Lifesteal and Tough if an ally died this round.',NULL,NULL,'"Waves of cold undead hands pulled down her companions. Only she remained, a gleaming beacon of justice whose blade seemed to sing the names of the fallen with every swing." - Demacian Ensign','SIXMOREVODKA','Radiant Guardian','01DE015','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (272,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ029.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ029-full.png''}]','Piltover & Zaun','PiltoverZaun',3,4,3,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Create in hand an Epic card from your regions.','Last Breath: Create in hand an Epic card from your regions.',NULL,NULL,'"I was an angry man, then, and broke my competitors as I accrued money and fame. I now direct my fortune toward altruism, and hope that my penitent winter will absolve me of my misdeeds."','SIXMOREVODKA','Eminent Benefactor','01PZ029','[''Last Breath'']','[''LastBreath'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (273,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX050.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX050-full.png''}]','Noxus','Noxus',0,2,0,'Deal 1 to ALL battling units.','Deal 1 to ALL battling units.',NULL,NULL,'"Dance with me!" - Katarina','Rafael Zanchetin','Death Lotus','01NX050','[''Fast'']','[''Fast'']','Fast','Fast','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (274,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T1-full.png''}]','Piltover & Zaun','PiltoverZaun',0,0,1,NULL,NULL,NULL,NULL,'"TODAY I EMBARK UPON A NEW SCIENTIFIC ADVENTURE: AUTOMATONS! As the saying goes, it takes a great mind to create great things! Who said that, you ask? Why, ME!" - Heimerdinger''s Lab Notes, Preface','SIXMOREVODKA','Mk0: Windup Shredder','01PZ056T1','[''Challenger'']','[''Challenger'']',NULL,NULL,'None','None','TECH','[''TECH'']',NULL,'Unit',0,'Set1');
INSERT INTO "API" VALUES (275,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO031.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO031-full.png''}]','Ionia','Ionia',3,6,5,'Your <link=keyword.Burst><sprite name=Burst><style=Keyword>Burst</style></link> spells cost 1 less.','Your Burst spells cost 1 less.',NULL,NULL,'Its songs could be heard from the villages--long, low waves of sound rippling from sky to hillside, each as formless and strange as the afternoon clouds.','SIXMOREVODKA','Cloud Drinker','01IO031','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (276,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE003.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE003-full.png''}]','Demacia','Demacia',2,4,3,'<link=vocab.Play><style=Vocab>Play</style></link>: Grant an ally +2|+2.','Play: Grant an ally +2|+2.',NULL,NULL,'"Yes, they are beautiful. But like any fine instrument, they only reveal their true beauty in the hands of a master." ','SIXMOREVODKA','Laurent Bladekeeper','01DE003','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (277,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR023.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR023-full.png''}]','Freljord','Freljord',0,12,0,'Summon the top ally from your deck now and EACH <link=vocab.RoundStart><style=Vocab>Round Start</style></link>.','Summon the top ally from your deck now and EACH Round Start.',NULL,NULL,'There will come a day when an unmistakable call will resound through the Freljord. On that day, all will rise to answer it, for it announces that our ancient enemies have emerged once again.','SIXMOREVODKA','Warmother''s Call','01FR023','[''Slow'']','[''Slow'']','Slow','Slow','EPIC','Epic',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (278,'[]','[''01PZ033T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ033.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ033-full.png''}]','Piltover & Zaun','PiltoverZaun',0,5,0,'If you''ve played <style=Variable>20</style> cards with different names this game, summon <link=card.summon><style=AssociatedCard>Catastrophe</style></link>. <style=Variable></style>','If you''ve played 20 cards with different names this game, summon Catastrophe. ',NULL,NULL,'"In the end, all of us who worked toward von Yipp''s vision were deceived. We knew not what we wrought--what terrible power we would unleash." - Piltovan Project Engineer','Kudos Productions','Purrsuit of Perfection','01PZ033','[''Slow'']','[''Slow'']','Slow','Slow','EPIC','Epic',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (279,'[]','[''01SI033'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI033T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI033T1-full.png''}]','Shadow Isles','ShadowIsles',0,0,0,'Deal damage to the enemy Nexus equal to half its Health, rounded up.','Deal damage to the enemy Nexus equal to half its Health, rounded up.',NULL,NULL,'Half a blade for half a man. A weapon broken as its wielder''s vow, broken as the king it was sworn to protect, broken as the kingdom of shadow that once was blessed.','Kudos Productions','Blade of Ledros','01SI033T1','[''Skill'']','[''Skill'']',NULL,NULL,'None','None',NULL,'[]',NULL,'Ability',0,'Set1');
INSERT INTO "API" VALUES (280,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ051.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ051-full.png''}]','Piltover & Zaun','PiltoverZaun',2,5,3,'All of your spells and skills deal 1 extra damage.','All of your spells and skills deal 1 extra damage.',NULL,NULL,'"You want extra boom, do ya? Well, you''ve come to the right place!"','SIXMOREVODKA','Funsmith','01PZ051','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (281,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI028.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI028-full.png''}]','Shadow Isles','ShadowIsles',0,3,0,'Summon an exact copy of an ally. It''s <link=keyword.Ephemeral><sprite name=Ephemeral><style=Keyword>Ephemeral</style></link> and 1|1.','Summon an exact copy of an ally. It''s Ephemeral and 1|1.',NULL,NULL,'"I lifted the body from the water to identify the poor soul. As I laid my hand upon its shoulder, it turned and showed its face. It was... me?" - Arie Wrence, Demacian Soldier','Max Grecke','Splinter Soul','01SI028','[''Slow'']','[''Slow'']','Slow','Slow','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (282,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI025.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI025-full.png''}]','Shadow Isles','ShadowIsles',0,6,0,'Kill an ally to deal damage equal to its Power to anything.','Kill an ally to deal damage equal to its Power to anything.',NULL,NULL,'Killing means nothing to those who cannot know death.','Kudos Productions','Atrocity','01SI025','[''Fast'']','[''Fast'']','Fast','Fast','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
