INSERT INTO "API" VALUES (293,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI046.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI046-full.png''}]','Shadow Isles','ShadowIsles',0,3,0,'Revive a random ally that died this round.','Revive a random ally that died this round.',NULL,NULL,'"The Mist severs spirit from flesh, leaving behind a foul parody of life. I have seen it corrupt my lands, so I go now to those cursed isles, to end this." - Arie Wrence, Dauntless Vindicator','Rafael Zanchetin','Mist''s Call','01SI046','[''Fast'']','[''Fast'']','Fast','Fast','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
