INSERT INTO "API" VALUES (296,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX033.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX033-full.png''}]','Noxus','Noxus',4,5,3,'When I''m summoned, draw 1 for each 5+ Power ally you have.','When I''m summoned, draw 1 for each 5+ Power ally you have.',NULL,NULL,'"It takes a ruthlessly discerning eye to select those worthy enough to become part of the Trifarian Legion, but she can sort the wolves from the sheep a mile away." - Legion General','SIXMOREVODKA','Trifarian Assessor','01NX033','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (297,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE032.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE032-full.png''}]','Demacia','Demacia',0,3,0,'Give an ally <link=keyword.Barrier><sprite name=Barrier><style=Keyword>Barrier</style></link> this round.','Give an ally Barrier this round.',NULL,NULL,'"The world can turn its back on you when you''re different. People say your differences make you weak--but they make us strong, compassionate. Even in the darkest times, I''ll protect you!" - Lux','Kudos Productions','Prismatic Barrier','01DE032','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (298,'[]','[''01NX006T3'', ''01NX006T4'', ''01NX006'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX006T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX006T1-full.png''}]','Noxus','Noxus',6,5,6,'<link=keyword.AttackSkillMark><sprite name=AttackSkillMark><style=Keyword>Attack</style></link>: For each attacking ally other than <link=card.level1><style=AssociatedCard>Vladimir</style></link>, deal 1 to it and <link=keyword.Drain><style=Keyword>drain</style></link> 1 from the enemy Nexus.','Attack: For each attacking ally other than Vladimir, deal 1 to it and drain 1 from the enemy Nexus.',NULL,NULL,'"Do you find my little fête banal, darling? Then let me give you a real show."','SIXMOREVODKA','Vladimir','01NX006T1','[''Regeneration'']','[''Regeneration'']',NULL,NULL,'None','None',NULL,'[]','Champion','Unit',0,'Set1');
INSERT INTO "API" VALUES (299,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ023.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ023-full.png''}]','Piltover & Zaun','PiltoverZaun',2,4,3,'When you summon a 1 cost ally, grant it +2|+2.','When you summon a 1 cost ally, grant it +2|+2.',NULL,NULL,'"Today I present to the committee my newest invention, as demonstrated by my esteemed colleague..."','SIXMOREVODKA','Professor von Yipp','01PZ023','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (300,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T4.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T4-full.png''}]','Piltover & Zaun','PiltoverZaun',1,1,1,NULL,NULL,NULL,NULL,'"It occurred to me earlier that--with only two hands--I can only maximally operate two wrenches! My solution: MORE HANDS. Oho! I jest. A WRENCHBOT!" - Heimerdinger''s Lab Notes, Vol. 1','SIXMOREVODKA','Mk1: Wrenchbot','01PZ056T4','[]','[]',NULL,NULL,'None','None','TECH','[''TECH'']',NULL,'Unit',0,'Set1');
INSERT INTO "API" VALUES (301,'[]','[''01FR039T2'', ''01FR039T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR039.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR039-full.png''}]','Freljord','Freljord',8,8,4,NULL,NULL,'If I would die, I Level Up instead.','If I would die, I Level Up instead.','"Do not die for your cause. Live for it..."','SIXMOREVODKA','Tryndamere','01FR039','[''Overwhelm'']','[''Overwhelm'']',NULL,NULL,'Champion','Champion',NULL,'[]','Champion','Unit',1,'Set1');
INSERT INTO "API" VALUES (302,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR027.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR027-full.png''}]','Freljord','Freljord',4,4,5,NULL,NULL,NULL,NULL,'Avarosan folk tales speak of "Old Uncle Elnuk", a stubborn old grouch who wanted nothing more than a warm patch of grass and an argument to dig his heel into. ','SIXMOREVODKA','Bull Elnuk','01FR027','[]','[]',NULL,NULL,'COMMON','Common','ELNUK','[''ELNUK'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (303,'[]','[''01SI002'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI050.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI050-full.png''}]','Shadow Isles','ShadowIsles',0,6,0,'Summon 3 <link=card.summon><style=AssociatedCard>Spiderlings</style></link>, then grant Spider allies +1|+0. ','Summon 3 Spiderlings, then grant Spider allies +1|+0. ',NULL,NULL,'They''re hungriest when they hatch.','Kudos Productions','Brood Awakening','01SI050','[''Slow'']','[''Slow'']','Slow','Slow','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (304,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR057.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR057-full.png''}]','Freljord','Freljord',0,7,0,'Give all allies +2|+2 and <link=keyword.Overwhelm><sprite name=Overwhelm><style=Keyword>Overwhelm</style></link> this round.','Give all allies +2|+2 and Overwhelm this round.',NULL,NULL,'A lone howl echoed through the night, followed by another, then another. Within moments, the pack howled as one--a chorus of frenzied voices calling out for blood.','Kudos Productions','Pack Mentality','01FR057','[''Slow'']','[''Slow'']','Slow','Slow','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (305,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ024.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ024-full.png''}]','Piltover & Zaun','PiltoverZaun',4,5,4,'Grant me +4|+0 and <link=keyword.Quick Strike><sprite name=QuickStrike><style=Keyword>Quick Attack</style></link> once you''ve cast a 6+ cost spell this game.','Grant me +4|+0 and Quick Attack once you''ve cast a 6+ cost spell this game.',NULL,NULL,'Name: Klas Henwick, Age: 51, License Type: Class 2 Conditional, Status: Revoked, Comments: Ignored repeated warnings to reduce output following lab explosion (Case 13X764NM). DO NOT PERMIT ENTRY.','SIXMOREVODKA','Unstable Voltician','01PZ024','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (306,'[]','[''01SI014'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI016.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI016-full.png''}]','Shadow Isles','ShadowIsles',4,4,3,'<link=vocab.Allegiance><style=Vocab>Allegiance</style></link>: Summon a <link=card.create><style=AssociatedCard>Mistwraith</style></link>.','Allegiance: Summon a Mistwraith.',NULL,NULL,'She appears without a sound. The terrors that follow her are far less subtle.','SIXMOREVODKA','Wraithcaller','01SI016','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (307,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO042.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO042-full.png''}]','Ionia','Ionia',1,1,1,'When you summon an ally, give me +1|+1 this round.','When you summon an ally, give me +1|+1 this round.',NULL,NULL,'"What''s the point of fighting if there''s no one to see your moves?"','SIXMOREVODKA','Sparring Student','01IO042','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (308,'[]','[''01FR038T2'', ''01FR038'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR038T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR038T1-full.png''}]','Freljord','Freljord',0,3,0,'<link=keyword.Frostbite><sprite name=Frostbite><style=Keyword>Frostbite</style></link> an enemy.INSERT INTO "API" VALUES (309,'[]','[''01FR021T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR021.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR021-full.png''}]','Freljord','Freljord',5,5,8,'<link=keyword.AttackSkillMark><sprite name=AttackSkillMark><style=Keyword>Attack</style></link>: Deal 1 to ALL battling units.','Attack: Deal 1 to ALL battling units.',NULL,NULL,'"Tarkaz fought harder and better than most. He took his defeat gracefully, I thought. Well, mostly..." - Tryndamere','SIXMOREVODKA','Tarkaz the Tribeless','01FR021','[]','[]',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (310,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR004.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR004-full.png''}]','Freljord','Freljord',0,1,0,'Give an ally +0|+2 this round.','Give an ally +0|+2 this round.',NULL,NULL,'"Rough out there, eh? Not to worry, the ''Owl serves up a special brew so strong it''ll pull the chill outta y''bones ''n grow hair on the chest of a newborn!" - Kindly Tavernkeeper','SIXMOREVODKA','Elixir of Iron','01FR004','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
