INSERT INTO "API" VALUES (313,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO050.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO050-full.png''}]','Ionia','Ionia',2,4,3,'<link=vocab.Allegiance><style=Vocab>Allegiance</style></link>: Summon two 1 cost allies from your deck.','Allegiance: Summon two 1 cost allies from your deck.',NULL,NULL,'Wherever she goes, she ensures that others can follow.','SIXMOREVODKA','Kinkou Wayfinder','01IO050','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (314,'[]','[''01NX043'', ''01NX042T2'', ''01NX042T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX042.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX042-full.png''}]','Noxus','Noxus',3,3,2,'<link=vocab.Play><style=Vocab>Play</style></link>: Create a <link=keyword.Fleeting><sprite name=Fleeting><style=Keyword>Fleeting</style></link> <link=card.create><style=AssociatedCard>Blade''s Edge</style></link> in hand.','Play: Create a Fleeting Blade''s Edge in hand.','I''ve <link=vocab.Strike><style=Vocab>struck</style></link> once. When I level up, <link=keyword.Recall><style=Keyword>Recall</style></link> me.','I''ve struck once. When I level up, Recall me.','"Nothing like a little Demacian target practice to sharpen the senses..."','SIXMOREVODKA','Katarina','01NX042','[''Quick Attack'']','[''QuickStrike'']',NULL,NULL,'Champion','Champion',NULL,'[]','Champion','Unit',1,'Set1');
INSERT INTO "API" VALUES (315,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI021.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI021-full.png''}]','Shadow Isles','ShadowIsles',3,2,1,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: The next time an <link=keyword.Ephemeral><sprite name=Ephemeral><style=Keyword>Ephemeral</style></link> ally attacks, revive me attacking.','Last Breath: The next time an Ephemeral ally attacks, revive me attacking.',NULL,NULL,'"She saw what? I see. Madness is a cruel mistress, apothecary. At least the others make some degree of sense." - Demacian surgeon','SIXMOREVODKA','Shark Chariot','01SI021','["Can''t Block", ''Ephemeral'', ''Last Breath'']','[''CantBlock'', ''Ephemeral'', ''LastBreath'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (316,'[]','[''01FR028'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR048.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR048-full.png''}]','Freljord','Freljord',3,3,3,'When I''m summoned, shuffle an <link=card.create><style=AssociatedCard>Enraged Yeti</style></link> into the top 3 cards of your deck.','When I''m summoned, shuffle an Enraged Yeti into the top 3 cards of your deck.',NULL,NULL,'"Caught nothing all week! Either those beasts are onto me, or something''s scaring ''em off..."','SIXMOREVODKA','Avarosan Trapper','01FR048','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (317,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ049.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ049-full.png''}]','Piltover & Zaun','PiltoverZaun',0,8,0,'Draw 3, then reduce those cards'' costs by 1.','Draw 3, then reduce those cards'' costs by 1.',NULL,NULL,'PROGRESS DAY!
INSERT INTO "API" VALUES (318,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO048.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO048-full.png''}]','Ionia','Ionia',4,5,3,NULL,NULL,NULL,NULL,'"Your order has thrust us from our lands. You''ve proved your power, Master Zed. Now let me prove that I too am worthy of your teachings."','SIXMOREVODKA','Yusari','01IO048','[''Challenger'', ''Elusive'']','[''Challenger'', ''Elusive'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (319,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR017.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR017-full.png''}]','Freljord','Freljord',3,5,3,'<link=vocab.Play><style=Vocab>Play</style></link>: For the top 6 cards in your deck, summon each Elnuk and shuffle the rest into your deck.','Play: For the top 6 cards in your deck, summon each Elnuk and shuffle the rest into your deck.',NULL,NULL,'"Avarosans are like elnuks--dull-eyed grass-eaters easily felled by the unscarred. It is by numbers alone that they stay alive." - Vrynna, Scarmother','SIXMOREVODKA','Troop of Elnuks','01FR017','[]','[]',NULL,NULL,'COMMON','Common','ELNUK','[''ELNUK'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (320,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI032.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI032-full.png''}]','Shadow Isles','ShadowIsles',3,4,3,'<link=vocab.Play><style=Vocab>Play</style></link>: Kill an ally, then revive it.','Play: Kill an ally, then revive it.',NULL,NULL,'There was a time when she sat with her father--a lord curator--as he studied the dusty tomes. He hoped one day she would take on the mantle. But not like this.','SIXMOREVODKA','Chronicler of Ruin','01SI032','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (321,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ006.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ006-full.png''}]','Piltover & Zaun','PiltoverZaun',6,10,6,'Reduce my cost by 1 for each spell you''ve cast this game.','Reduce my cost by 1 for each spell you''ve cast this game.',NULL,NULL,'You have twenty seconds to comply.','SIXMOREVODKA','Plaza Guardian','01PZ006','[''Quick Attack'']','[''QuickStrike'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (322,'[]','[''01IO013'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO007.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO007-full.png''}]','Ionia','Ionia',3,4,3,'<link=vocab.Strike><style=Vocab>Strike</style></link>: Create a <link=card.summon><style=AssociatedCard>Shadow Fiend</style></link> in hand.','Strike: Create a Shadow Fiend in hand.',NULL,NULL,'“Run. Fight. Cower. It matters not, the shadows have come for you.”','SIXMOREVODKA','Ren Shadowblade','01IO007','[''Quick Attack'']','[''QuickStrike'']',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (323,'[]','[''01FR024T5'', ''01FR024T1'', ''01FR024'', ''01FR024T4'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR024T3.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR024T3-full.png''}]','Freljord','Freljord',3,6,5,'<link=keyword.AttackSkillMark><sprite name=AttackSkillMark><style=Keyword>Attack</style></link>: Deal 2 to all enemies and the enemy Nexus.INSERT INTO "API" VALUES (324,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI058.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI058-full.png''}]','Shadow Isles','ShadowIsles',4,5,3,'<link=vocab.Play><style=Vocab>Play</style></link>: Kill an ally to summon a random follower that costs 2 more.','Play: Kill an ally to summon a random follower that costs 2 more.',NULL,NULL,'Spirits, lend your voices to mine! Together, we will call down a darkness unending!','JiHun Lee','Ethereal Remitter','01SI058','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (325,'[]','[''01PZ010'', ''01PZ022'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ053.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ053-full.png''}]','Piltover & Zaun','PiltoverZaun',2,2,2,'When I''m summoned, create a <link=card.create><style=AssociatedCard>Mushroom Cloud</style></link> in hand.','When I''m summoned, create a Mushroom Cloud in hand.',NULL,NULL,'"Mhm, that''s right! Clumps of ''em, sneakin'' around! They SEEM crazy, but you just don''t see. Not like me! They''ve big plans! Big plans. Puffcaps. Cheese... sorbet. Where was I?" - Puffcap Peddler','SIXMOREVODKA','Clump of Whumps','01PZ053','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (326,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO053.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO053-full.png''}]','Ionia','Ionia',2,3,2,'<link=keyword.Enlightened><style=Keyword>Enlightened</style></link>: I have +4|+4.','Enlightened: I have +4|+4.',NULL,NULL,'"War is fostered by our basest instincts. But instinct has no power over our highest virtues: trust, patience, and contemplation."','SIXMOREVODKA','Emerald Awakener','01IO053','[''Lifesteal'']','[''Lifesteal'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (327,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR046.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR046-full.png''}]','Freljord','Freljord',0,3,0,'Grant a damaged ally +3|+3.','Grant a damaged ally +3|+3.',NULL,NULL,'"... Though his wounds were great, Braum threw back his head and laughed. For he knew that dire times are when heroes are made!" - The Tale of Braum','SIXMOREVODKA','Take Heart','01FR046','[''Burst'']','[''Burst'']','Burst','Burst','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (328,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX045.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX045-full.png''}]','Noxus','Noxus',7,7,4,NULL,NULL,NULL,NULL,'"Next up, CLAWS! Last time was a BLOODY takedown versus the Psycho Five... now the Psycho Three. Allllright! Takin'' bets on today''s victim! Four to one!" - Karl, Arena Bookie','SIXMOREVODKA','Savage Reckoner','01NX045','[''Overwhelm'', ''Challenger'']','[''Overwhelm'', ''Challenger'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (329,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO004.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO004-full.png''}]','Ionia','Ionia',0,1,0,'Heal an ally or your Nexus 3.','Heal an ally or your Nexus 3.',NULL,NULL,'Every generation, region, and family has its own home remedy--though some are undeniably more effective than others.','Kudos Productions','Health Potion','01IO004','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (330,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE027.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE027-full.png''}]','Demacia','Demacia',0,3,0,'Give all allies <link=keyword.Challenger><sprite name=Challenger><style=Keyword>Challenger</style></link> this round.','Give all allies Challenger this round.',NULL,NULL,'"There''s not a Demacian alive who would refuse a Laurent''s lesson in swordsmanship. Or survived one, for that matter." - Fiora','Kudos Productions','En Garde','01DE027','[''Burst'']','[''Burst'']','Burst','Burst','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
