INSERT INTO "API" VALUES (333,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR012.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR012-full.png''}]','Freljord','Freljord',0,5,0,'Get an empty mana gem and heal your Nexus 3.','Get an empty mana gem and heal your Nexus 3.',NULL,NULL,'Neither ruby nor sapphire surpass the luster of the aeon stone--a brilliant gem with legendary restorative properties. ','Kudos Production','Catalyst of Aeons','01FR012','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
