INSERT INTO "API" VALUES (344,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ039.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ039-full.png''}]','Piltover & Zaun','PiltoverZaun',0,3,0,'To play, discard 1.INSERT INTO "API" VALUES (345,'[]','[''01DE022'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE038.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE038-full.png''}]','Demacia','Demacia',4,3,2,'The first time an allied <link=card.luc1><style=AssociatedCard>Lucian</style></link> dies, grant me +1|+1 and <link=keyword.Double Strike><sprite name=DoubleStrike><style=Keyword>Double Attack</style></link>.','The first time an allied Lucian dies, grant me +1|+1 and Double Attack.',NULL,NULL,'"Our Sentinels are the first line of defense between the tide of restless undead and the realms of man. We hit first, hit hard, and NEVER back down when the lives of our companions are on the line."','SIXMOREVODKA','Senna, Sentinel of Light','01DE038','[''Quick Attack'']','[''QuickStrike'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (346,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR010.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR010-full.png''}]','Freljord','Freljord',0,4,0,'Grant 2 allies +0|+3.','Grant 2 allies +0|+3.',NULL,NULL,'"I will be a torch in your heart, a shield at your side. Let me find strength to protect us and our kin, and may our lives flow together as the blood that seals this oath." - Tryndamere','SIXMOREVODKA','Bloodsworn Pledge','01FR010','[''Burst'']','[''Burst'']','Burst','Burst','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (347,'[]','[''01IO052T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO052.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO052-full.png''}]','Ionia','Ionia',1,2,2,'When I''m summoned, summon a <link=card.summon><style=AssociatedCard>Navori Brigand</style></link> with my stats.','When I''m summoned, summon a Navori Brigand with my stats.',NULL,NULL,'“I was a traveling musician, known in every village ''ere to the Placidium--until the Noxians came. Now I''m scraping by on stolen coin. Mother was right, should''ve been a healer... ”','SIXMOREVODKA','Navori Highwayman','01IO052','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (348,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO030.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO030-full.png''}]','Ionia','Ionia',6,7,5,NULL,NULL,NULL,NULL,'"The sky itself heaved as coils of clouds and powerful winds flattened our brigade. We tried to follow it, but who can chase the wind?" - Legion General','SIXMOREVODKA','The Empyrean','01IO030','[''Elusive'']','[''Elusive'']',NULL,NULL,'EPIC','Epic','DRAGON','[]',NULL,'Unit',1,'Set1');
