INSERT INTO "API" VALUES (351,'[]','[''01NX006T3'', ''01NX006T2'', ''01NX006T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX006.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX006-full.png''}]','Noxus','Noxus',5,5,5,'<link=keyword.AttackSkillMark><sprite name=AttackSkillMark><style=Keyword>Attack</style></link>: For each attacking ally other than <link=card.level1><style=AssociatedCard>Vladimir</style></link>, deal 1 to it and 1 to the enemy Nexus.','Attack: For each attacking ally other than Vladimir, deal 1 to it and 1 to the enemy Nexus.','You''ve had 6+ allies survive damage<style=Variable></style>.','You''ve had 6+ allies survive damage.','Vicious. Cold. Cruel. Intriguing. Perceptive. Charming.
