INSERT INTO "API" VALUES (355,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX008.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX008-full.png''}]','Noxus','Noxus',4,4,3,'<link=vocab.Allegiance><style=Vocab>Allegiance</style></link>: Grant me +1|+1 and <link=keyword.Overwhelm><sprite name=Overwhelm><style=Keyword>Overwhelm</style></link>.','Allegiance: Grant me +1|+1 and Overwhelm.',NULL,NULL,'This particular unit does use horses, just not for riding. The beasts find them delicious.','SIXMOREVODKA','Basilisk Rider','01NX008','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
