INSERT INTO "API" VALUES (357,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE018.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE018-full.png''}]','Demacia','Demacia',0,1,0,'Give an ally +1|+1 this round.','Give an ally +1|+1 this round.',NULL,NULL,'"Undead fight like they''ve got no tomorrow. We''ll make sure they won’t get one." - Lucian
INSERT INTO "API" VALUES (358,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI020.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI020-full.png''}]','Shadow Isles','ShadowIsles',4,7,4,'When I''m summoned, revive the <link=vocab.Strongest><style=Vocab>Strongest</style></link> dead allied champion.','When I''m summoned, revive the Strongest dead allied champion.',NULL,NULL,'What use does a dying candle have, other than to light its successor?','SIXMOREVODKA','The Rekindler','01SI020','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
