INSERT INTO "API" VALUES (361,'[]','[''01SI042T1'', ''01SI042T2'', ''01SI024'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI042.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI042-full.png''}]','Shadow Isles','ShadowIsles',5,6,5,'<link=vocab.Attack><style=Vocab>Attack</style></link>: Summon 2 attacking <link=card.summon><style=AssociatedCard>Spectral Riders</style></link>.','Attack: Summon 2 attacking Spectral Riders.','You''ve attacked with 7+ <link=keyword.Ephemeral><sprite name=Ephemeral><style=Keyword>Ephemeral</style></link> allies<style=Variable></style>.','You''ve attacked with 7+ Ephemeral allies.','That''s not thunder. The Shadow of War is on the horizon.','SIXMOREVODKA','Hecarim','01SI042','[''Overwhelm'']','[''Overwhelm'']',NULL,NULL,'Champion','Champion',NULL,'[]','Champion','Unit',1,'Set1');
INSERT INTO "API" VALUES (362,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE009.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE009-full.png''}]','Demacia','Demacia',3,2,2,'<link=vocab.Play><style=Vocab>Play</style></link>: Give an ally <link=keyword.Barrier><sprite name=Barrier><style=Keyword>Barrier</style></link> this round.','Play: Give an ally Barrier this round.',NULL,NULL,'"We are a prosperous nation because each warrior''s fate is a coin we will never be content to spend." - King Jarvan III','SIXMOREVODKA','Brightsteel Protector','01DE009','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
