INSERT INTO "API" VALUES (364,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ009.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ009-full.png''}]','Piltover & Zaun','PiltoverZaun',2,3,3,NULL,NULL,NULL,NULL,'"Personal flying machines? A pipe dream! I just had my apprentice throw the latest prototype out, in fact. Now, where is he?" - Piltovan Engineer','SIXMOREVODKA','Amateur Aeronaut','01PZ009','[''Elusive'']','[''Elusive'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (365,'[]','[''01IO032T1'', ''01IO032'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO032T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO032T2-full.png''}]','Ionia','Ionia',0,6,0,'Swap 2 allies. Give them <link=keyword.Barrier><sprite name=Barrier><style=Keyword>Barrier</style></link> this round.INSERT INTO "API" VALUES (366,'[]','[''01SI035T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI035.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI035-full.png''}]','Shadow Isles','ShadowIsles',7,8,5,'<link=keyword.PlaySkillMark><sprite name=PlaySkillMark><style=Keyword>Play</style></link>: Kill the 2 <link=keyword.Weakest><style=Keyword>Weakest</style></link> enemies if an ally died this round.','Play: Kill the 2 Weakest enemies if an ally died this round.',NULL,NULL,'"We were told... they called it a legend''s journey. We were going to... for Demacia''s future. We sailed with such hope. But all... all those lives... for what?" - Arie Wrence, Demacian Soldier','SIXMOREVODKA','Rhasa the Sunderer','01SI035','[''Fearsome'']','[''Fearsome'']',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (367,'[]','[''01FR024T4'', ''01FR024T3'', ''01FR024T2'', ''01FR024T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR024.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR024-full.png''}]','Freljord','Freljord',2,6,4,'<link=keyword.AttackSkillMark><sprite name=AttackSkillMark><style=Keyword>Attack</style></link>: Deal 1 to all enemies and the enemy Nexus.INSERT INTO "API" VALUES (368,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX034.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX034-full.png''}]','Noxus','Noxus',1,1,1,NULL,NULL,NULL,NULL,'"Noxus has no room for... for weakn--Will someone get this DAMNED THING OFF ME?!" - Darius','SIXMOREVODKA','Affectionate Poro','01NX034','[''Challenger'']','[''Challenger'']',NULL,NULL,'COMMON','Common','PORO','[''PORO'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (369,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ042.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ042-full.png''}]','Piltover & Zaun','PiltoverZaun',1,2,3,'<link=vocab.Support><style=Vocab>Support</style></link>: Give my supported ally <link=keyword.Elusive><sprite name=Elusive><style=Keyword>Elusive</style></link> this round.','Support: Give my supported ally Elusive this round.',NULL,NULL,'For many Piltovans, the great unknown is explored through science and invention, safe within their City of Progress. But a handful embark for the horizon to discover a much greater unknown: the world.','SIXMOREVODKA','Intrepid Mariner','01PZ042','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (370,'[]','[''01DE042T2'', ''01DE042T1'', ''01DE042T3'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE042.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE042-full.png''}]','Demacia','Demacia',4,6,5,NULL,NULL,'I''ve seen you cast 6+ mana of spells<style=Variable></style>. When I level up, create a <link=card.warcry><style=AssociatedCard>Final Spark</style></link> in hand.','I''ve seen you cast 6+ mana of spells. When I level up, create a Final Spark in hand.','"I''ve always known there''s something different about me... a light from within. I''m not sure what it is, but I have to find out!" ','SIXMOREVODKA','Lux','01DE042','[''Barrier'']','[''Barrier'']',NULL,NULL,'Champion','Champion',NULL,'[]','Champion','Unit',1,'Set1');
INSERT INTO "API" VALUES (371,'[]','[''01DE045'', ''01DE045T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE045T2.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE045T2-full.png''}]','Demacia','Demacia',0,4,0,'Give an ally +3|+0 and <link=keyword.Barrier><sprite name=Barrier><style=Keyword>Barrier</style></link> this round.INSERT INTO "API" VALUES (372,'[]','[''01NX020'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX035.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX035-full.png''}]','Noxus','Noxus',2,1,1,'When I''m summoned, move <link=card.dravenRef><style=AssociatedCard>Draven</style></link> to the top of your deck if you don''t have him in hand or in play.','When I''m summoned, move Draven to the top of your deck if you don''t have him in hand or in play.',NULL,NULL,'"You want an autograph? Get... Get in line, pal!"','SIXMOREVODKA','Draven''s Biggest Fan','01NX035','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (373,'[]','[''01FR024T3'', ''01FR024'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR024T5.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR024T5-full.png''}]','Freljord','Freljord',0,0,0,'Deal 2 to all enemies and the enemy Nexus.','Deal 2 to all enemies and the enemy Nexus.',NULL,NULL,'The storm that comes before the calm.','SIXMOREVODKA','Glacial Storm','01FR024T5','[''Skill'']','[''Skill'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Ability',0,'Set1');
INSERT INTO "API" VALUES (374,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX026.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX026-full.png''}]','Noxus','Noxus',5,3,4,NULL,NULL,NULL,NULL,'"Recklessness is a fault. Tempered by the Legion, it becomes a tool." - Jericho Swain','SIXMOREVODKA','Reckless Trifarian','01NX026','["Can''t Block"]','[''CantBlock'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (375,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI004.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI004-full.png''}]','Shadow Isles','ShadowIsles',5,3,5,NULL,NULL,NULL,NULL,'Some fleeing the Ruination tried diving beneath the waves, believing the corruption wouldn''t seep into the depths. They were wrong.','SIXMOREVODKA','Darkwater Scourge','01SI004','[''Ephemeral'', ''Lifesteal'']','[''Ephemeral'', ''Lifesteal'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (376,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO046.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO046-full.png''}]','Ionia','Ionia',0,2,0,'<link=keyword.Stun><sprite name=Stunned><style=Keyword>Stun</style></link> an attacking enemy.','Stun an attacking enemy.',NULL,NULL,'"Hasegi!"- Yasuo','Max Grecke','Steel Tempest','01IO046','[''Fast'']','[''Fast'']','Fast','Fast','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (377,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE039.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE039-full.png''}]','Demacia','Demacia',2,1,2,NULL,NULL,NULL,NULL,'"Each night before bed, my mother would tell me stories of Demacia''s greatest heroes as she sharpened her sword. My dreams were full of adventures, and today I''ll begin a story all my own."','SIXMOREVODKA','Cithria of Cloudfield','01DE039','[]','[]',NULL,NULL,'COMMON','Common','ELITE','[''ELITE'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (378,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T6.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ056T6-full.png''}]','Piltover & Zaun','PiltoverZaun',6,6,1,NULL,NULL,NULL,NULL,'"I seem to have misplaced my latest work. And my mezzanine. I''m concerned about my bot, but the shrieking from the ceramics research laboratory gives me hope!"
INSERT INTO "API" VALUES (379,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE056.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE056-full.png''}]','Demacia','Demacia',2,4,2,'<link=vocab.Attack><style=Vocab>Attack</style></link>: Grant me +2|+2.','Attack: Grant me +2|+2.',NULL,NULL,'The battle cry sounds, and my feet are already turning over the soil. I need nothing but my lady''s order to know my destiny and enact her will.','SIXMOREVODKA','Vanguard Firstblade','01DE056','[]','[]',NULL,NULL,'COMMON','Common','ELITE','[''ELITE'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (380,'[]','[''01NX006T1'', ''01NX006'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX006T3.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX006T3-full.png''}]','Noxus','Noxus',0,2,0,'Deal 1 to an ally and give another ally +2|+2 this round.INSERT INTO "API" VALUES (381,'[]','[''01FR043'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR043T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR043T1-full.png''}]','Freljord','Freljord',4,6,4,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Summon a <link=card.summon><style=AssociatedCard>Heart of the Fluft</style></link>.','Last Breath: Summon a Heart of the Fluft.',NULL,NULL,'"... At first she didn''t know what the little ones could do. But then another appeared, and another, ''til the hall was full of them! And every poro gathered--" 
INSERT INTO "API" VALUES (382,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE029.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE029-full.png''}]','Demacia','Demacia',2,1,1,'When you summon another ally, grant me <link=keyword.Challenger><sprite name=Challenger><style=Keyword>Challenger</style></link>.','When you summon another ally, grant me Challenger.',NULL,NULL,'These relatives of the silverwing raptors have the predatory instincts of their cousins alongside a dogged unfamiliarity with their own comparatively diminutive size.','SIXMOREVODKA','Fleetfeather Tracker','01DE029','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (383,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO037.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO037-full.png''}]','Ionia','Ionia',0,4,0,'Give an ally <link=keyword.Barrier><sprite name=Barrier><style=Keyword>Barrier</style></link> and <link=keyword.Lifesteal><sprite name=Lifesteal><style=Keyword>Lifesteal</style></link> this round.','Give an ally Barrier and Lifesteal this round.',NULL,NULL,'"This blade was once my father''s. May it bring you the strength that I once lacked." - Shen','Kudos Productions','Spirit''s Refuge','01IO037','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (384,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX027.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX027-full.png''}]','Noxus','Noxus',0,1,0,'Give an ally +3|+0 this round.','Give an ally +3|+0 this round.',NULL,NULL,'"When the open hand is declined, there''s always the fist." - Noxian Axiom','Kudos Productions','Elixir of Wrath','01NX027','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (385,'[]','[''01FR024T3'', ''01FR024T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR024T4.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR024T4-full.png''}]','Freljord','Freljord',0,1,1,NULL,NULL,'<link=vocab.RoundStart><style=Vocab>Round Start</style></link>: If you''re <link=keyword.Enlightened><style=Keyword>Enlightened</style></link>, transform me back into <link=card.level1><style=AssociatedCard>Anivia</style></link> and Level Up.','Round Start: If you''re Enlightened, transform me back into Anivia and Level Up.','In the depths of winter''s cold embrace, the Freljord''s guardian awaits the hour of her return.','SIXMOREVODKA','Eggnivia','01FR024T4','[]','[]',NULL,NULL,'None','None',NULL,'[]','Champion','Unit',0,'Set1');
INSERT INTO "API" VALUES (386,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ026.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ026-full.png''}]','Piltover & Zaun','PiltoverZaun',0,2,0,'Grant an ally <link=keyword.Elusive><sprite name=Elusive><style=Keyword>Elusive</style></link>.','Grant an ally Elusive.',NULL,NULL,'"Pilties always think they know everything, but their maps only show the places we told ''em about! Nothing like local knowledge. Which you can have... for a price." - Ajuna Lem, Sumpsnipe Scavenger','Kudos Productions','Sumpworks Map','01PZ026','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (387,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE028.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE028-full.png''}]','Demacia','Demacia',5,5,5,NULL,NULL,NULL,NULL,'The Vanguard needed no drums, no music to keep time in their advance. Only the steady, even beat of hooves against soil.','SIXMOREVODKA','Vanguard Cavalry','01DE028','[''Tough'']','[''Tough'']',NULL,NULL,'COMMON','Common','ELITE','[''ELITE'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (388,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO043.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO043-full.png''}]','Ionia','Ionia',2,3,2,'<link=vocab.Strike><style=Vocab>Strike</style></link>: Draw a spell.','Strike: Draw a spell.',NULL,NULL,'"We are proud children of the First Lands, and the streams of her magic flow through our vastayan blood as they do through our realm."','SIXMOREVODKA','Rivershaper','01IO043','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (389,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ043.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ043-full.png''}]','Piltover & Zaun','PiltoverZaun',3,2,2,'<link=vocab.Nexus Strike><style=Vocab>Nexus Strike</style></link>: Create in hand an exact copy of a random spell from the enemy''s deck.','Nexus Strike: Create in hand an exact copy of a random spell from the enemy''s deck.',NULL,NULL,'Those cast below the City of Progress were expected to turn on each other. But instead they bonded, found their feet as one, and created a new home. It wasn''t much, but it was theirs. Zaun.','SIXMOREVODKA','Chempunk Pickpocket','01PZ043','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (390,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR032.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR032-full.png''}]','Freljord','Freljord',2,2,3,'When you cast a spell, grant the top ally in your deck +1|+1.','When you cast a spell, grant the top ally in your deck +1|+1.',NULL,NULL,'"Grant them keen ears to hear the wind''s approach, light feet to cross the coming snows, and sharp eyes to see beyond the veil of winter."','SIXMOREVODKA','Starlit Seer','01FR032','[''Imbue'']','[''Imbue'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (391,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO038.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO038-full.png''}]','Ionia','Ionia',3,3,3,'When I''m summoned, <link=keyword.Recall><style=Keyword>Recall</style></link> all other allies.','When I''m summoned, Recall all other allies.',NULL,NULL,'"Reflex and instinct are the only company I desire."','SIXMOREVODKA','Solitary Monk','01IO038','[''Elusive'']','[''Elusive'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (392,'[]','[''01FR052T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR052.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR052-full.png''}]','Freljord','Freljord',10,10,10,'<link=keyword.PlaySkillMark><sprite name=PlaySkillMark><style=Keyword>Play</style></link>: <link=keyword.Obliterate><style=Keyword>Obliterate</style></link> ALL followers with 4 or less Power in play and in hands.','Play: Obliterate ALL followers with 4 or less Power in play and in hands.',NULL,NULL,'"I dug myself out from the rubble to find a scar seared into the land around me. Smoldering ash lay where my companions had stood, and in the distance a looming form moved on..." - Bjerg the Wanderer','SIXMOREVODKA','She Who Wanders','01FR052','[''Regeneration'']','[''Regeneration'']',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (393,'[]','[''01FR028'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR051.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR051-full.png''}]','Freljord','Freljord',0,3,0,'If you have a Yeti, summon an <link=card.create><style=AssociatedCard>Enraged Yeti</style></link>. Otherwise, create it on top of your deck.','If you have a Yeti, summon an Enraged Yeti. Otherwise, create it on top of your deck.',NULL,NULL,'"... and this one has a mouth fulla big jagged teeths an'' smashy fists an super an-ger-y eyes an a HUUUGE TREE-SHAKING ROAR! Uncle Bjerg told me so!" - Ingvar the Younger','SIXMOREVODKA','Tall Tales','01FR051','[''Slow'']','[''Slow'']','Slow','Slow','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (394,'[]','[''01NX022'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX022.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX022-full.png''}]','Noxus','Noxus',0,3,0,'Kill a damaged unit to create a <link=keyword.Fleeting><sprite name=Fleeting><style=Keyword>Fleeting</style></link> <link=card.me><style=AssociatedCard>Noxian Guillotine</style></link> in hand.','Kill a damaged unit to create a Fleeting Noxian Guillotine in hand.',NULL,NULL,'To Darius, mercy is a deft blow.','SIXMOREVODKA','Noxian Guillotine','01NX022','[''Fast'']','[''Fast'']','Fast','Fast','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (395,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ047.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01PZ047-full.png''}]','Piltover & Zaun','PiltoverZaun',0,0,1,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Deal 1 to EACH Nexus.','Last Breath: Deal 1 to EACH Nexus.',NULL,NULL,'“I’d tell ya to wear a suit, but it gets muggy as a whump’s armpit down there. Gloves though, eh? An’ if you get that gunk on ya’, pray it don’t touch nothin’ important.” - Ziel, Zaunite Foreman','SIXMOREVODKA','Caustic Cask','01PZ047','[''Last Breath'', ''Ephemeral'']','[''LastBreath'', ''Ephemeral'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (396,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI026.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI026-full.png''}]','Shadow Isles','ShadowIsles',1,1,1,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Create in hand another <link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link> follower that costs 3 or less.','Last Breath: Create in hand another Last Breath follower that costs 3 or less.',NULL,NULL,'He held his breath as best he could, praying the warden would move on. Little did he know, this pursuit would just be the beginning of Thresh''s delighted torments…','SIXMOREVODKA','Warden''s Prey','01SI026','[''Last Breath'']','[''LastBreath'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (397,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO012T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO012T1-full.png''}]','Ionia','Ionia',0,3,0,'Give an ally +3|+0 this round.','Give an ally +3|+0 this round.',NULL,NULL,NULL,'SIXMOREVODKA','Discipline of Force','01IO012T1','[''Burst'']','[''Burst'']','Burst','Burst','None','None',NULL,'[]',NULL,'Spell',0,'Set1');
INSERT INTO "API" VALUES (398,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE013.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE013-full.png''}]','Demacia','Demacia',0,1,0,'Grant an ally <link=keyword.Tough><sprite name=Tough><style=Keyword>Tough</style></link>.','Grant an ally Tough.',NULL,NULL,'Demacian steel is known throughout the world for its superior strength. Its forging requires smiths of equal strength and repute.','Kudos Productions','Chain Vest','01DE013','[''Burst'']','[''Burst'']','Burst','Burst','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (399,'[]','[''01IO009T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO039.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO039-full.png''}]','Ionia','Ionia',0,3,0,'<link=keyword.Recall><style=Keyword>Recall</style></link> an ally to summon a <link=card.create><style=AssociatedCard>Living Shadow</style></link> in its place.','Recall an ally to summon a Living Shadow in its place.',NULL,NULL,'Do you face the enemy that you believe you see? Or is it a trick of the shadows?','Max Grecke','Shadowshift','01IO039','[''Fast'']','[''Fast'']','Fast','Fast','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (400,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX032.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX032-full.png''}]','Noxus','Noxus',5,4,5,'When I''m summoned, deal 1 to all other allies.','When I''m summoned, deal 1 to all other allies.',NULL,NULL,'"Even if I said ''no'', you''d drag me along. So... sure."','SIXMOREVODKA','Crimson Awakener','01NX032','[]','[]',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (401,'[]','[''01DE025'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE023.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE023-full.png''}]','Demacia','Demacia',3,3,3,'Create a <link=card.create><style=AssociatedCard>Detain</style></link> in hand once you''ve cast a 6+ cost spell this game.','Create a Detain in hand once you''ve cast a 6+ cost spell this game.',NULL,NULL,'"Forgive the intrusion, but we will require your full cooperation. We have been notified of some... ''unusual happenings''..."','SIXMOREVODKA','Mageseeker Investigator','01DE023','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (402,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX024.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX024-full.png''}]','Noxus','Noxus',5,5,4,'<link=vocab.Support><style=Vocab>Support</style></link>: Give my supported ally +3|+0 and <link=keyword.Overwhelm><sprite name=Overwhelm><style=Keyword>Overwhelm</style></link> this round.','Support: Give my supported ally +3|+0 and Overwhelm this round.',NULL,NULL,'"Shiraza is a great girlfriend--I mean friend--and we are in no way dating. But if we were, I would like her to know that I wish her a happy anniversary. Thank you, no more questions."','SIXMOREVODKA','Kato The Arm','01NX024','[]','[]',NULL,NULL,'EPIC','Epic',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (403,'[]','[''01SI002'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI040.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI040-full.png''}]','Shadow Isles','ShadowIsles',0,2,0,'<link=keyword.Drain><style=Keyword>Drain</style></link> 1 from a unit to summon a <link=card.create><style=AssociatedCard>Spiderling</style></link>.','Drain 1 from a unit to summon a Spiderling.',NULL,NULL,'"My... my lady! I didn''t realize you were such an... an arachnophile! Could you perhaps call them away from me? L-Lady Elise? Please?" - Lord Sassen, Hapless Aristocrat','Kudos Productions','Vile Feast','01SI040','[''Fast'']','[''Fast'']','Fast','Fast','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (404,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR034.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR034-full.png''}]','Freljord','Freljord',1,7,1,'When I''m summoned, grant me +1|+1 for each ally that has died.','When I''m summoned, grant me +1|+1 for each ally that has died.',NULL,NULL,'"Ah, old Bjerg''s been through a bit. Lost his crew up north, returned pale an'' gibberin'' months later. Now, it''s just "giant beasts" this and "huge claws" that. That poor man..." - Tavernkeeper','SIXMOREVODKA','They Who Endure','01FR034','[''Overwhelm'']','[''Overwhelm'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (405,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE051.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE051-full.png''}]','Demacia','Demacia',6,6,6,'<link=vocab.Attack><style=Vocab>Attack</style></link>: Give other battling allies +1|+1 and <link=keyword.Fearsome><sprite name=Fearsome><style=Keyword>Fearsome</style></link> this round.','Attack: Give other battling allies +1|+1 and Fearsome this round.',NULL,NULL,'"Legends, tales--they were never just fiction to me. They were adventure calling my name. I left Cloudfield to discover my own adventure, only to find I would have many. And they’re just beginning.”
INSERT INTO "API" VALUES (406,'[]','[''01IO056T1'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO056.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO056-full.png''}]','Ionia','Ionia',6,7,6,'<link=keyword.PlaySkillMark><sprite name=PlaySkillMark><style=Keyword>Play</style></link>: <link=keyword.Stun><sprite name=Stunned><style=Keyword>Stun</style></link> 2 enemies.','Play: Stun 2 enemies.',NULL,NULL,'"When I was a child, I asked my brother: ''Does the wind flee, or does it follow?'' He followed me then for guidance. I follow him now for justice."
INSERT INTO "API" VALUES (407,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO055.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01IO055-full.png''}]','Ionia','Ionia',0,2,0,'Grant <link=keyword.Barrier><sprite name=Barrier><style=Keyword>Barrier</style></link> to an ally in hand. INSERT INTO "API" VALUES (408,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI015.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI015-full.png''}]','Shadow Isles','ShadowIsles',0,9,0,'Kill ALL units.','Kill ALL units.',NULL,NULL,'To think something so pure as love could cause something so cruel and inescapable. ','Oliver Chipping','The Ruination','01SI015','[''Slow'']','[''Slow'']','Slow','Slow','EPIC','Epic',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (409,'[]','[''01SI052T2'', ''01SI052'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI052T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI052T1-full.png''}]','Shadow Isles','ShadowIsles',4,5,7,'The first time I attack this game, summon another attacking champion from your deck or hand.','The first time I attack this game, summon another attacking champion from your deck or hand.',NULL,NULL,'"You''re mine. Forever."Cling clang, oh the chains, the Warden''s right behind you...','SIXMOREVODKA','Thresh','01SI052T1','[''Challenger'']','[''Challenger'']',NULL,NULL,'None','None',NULL,'[]','Champion','Unit',0,'Set1');
INSERT INTO "API" VALUES (410,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX049.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX049-full.png''}]','Noxus','Noxus',0,1,0,'<link=keyword.Stun><sprite name=Stunned><style=Keyword>Stun</style></link> an enemy.','Stun an enemy.',NULL,NULL,'"Allow your enemies enough rope to hang themselves and you''ll save yourself the effort." - LeBlanc','Kudos Productions','Guile','01NX049','[''Slow'']','[''Slow'']','Slow','Slow','COMMON','Common',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (411,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR007.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR007-full.png''}]','Freljord','Freljord',3,4,3,'When I''m summoned, draw a unit with 5+ Power.','When I''m summoned, draw a unit with 5+ Power.',NULL,NULL,'"Y-You''ve gotta believe me! It was huge, I tell you, HUUUGE!"','SIXMOREVODKA','Babbling Bjerg','01FR007','[]','[]',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (412,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE054.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE054-full.png''}]','Demacia','Demacia',3,3,3,'When I''m summoned, draw a unit if an ally died this round.','When I''m summoned, draw a unit if an ally died this round.',NULL,NULL,'"Our fallen shall be remembered in every battle cry, in every swing of our swords, and every crash of our shields! Today, we shall be victorious!"','SIXMOREVODKA','Vanguard Redeemer','01DE054','[]','[]',NULL,NULL,'COMMON','Common','ELITE','[''ELITE'']',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (413,'[]','[''01DE012T1'', ''01DE012T2'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE012.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE012-full.png''}]','Demacia','Demacia',5,5,5,NULL,NULL,'I''ve <link=vocab.Strike><style=Vocab>struck</style></link> twice<style=Variable></style>.','I''ve struck twice.','Training and resilience are the way of a soldier. Even in the face of great peril, we will not falter.','SIXMOREVODKA','Garen','01DE012','[''Regeneration'']','[''Regeneration'']',NULL,NULL,'Champion','Champion','ELITE','[''ELITE'']','Champion','Unit',1,'Set1');
INSERT INTO "API" VALUES (414,'[]','[''01NX020'']','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX020T1.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01NX020T1-full.png''}]','Noxus','Noxus',0,0,0,'To play, discard 1.INSERT INTO "API" VALUES (415,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR003.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01FR003-full.png''}]','Freljord','Freljord',2,2,1,'<link=keyword.Last Breath><sprite name=LastBreath><style=Keyword>Last Breath</style></link>: Draw 1.','Last Breath: Draw 1.',NULL,NULL,'"Once I sought my place on distant battlefields. Now, I''ve found it beside my kin, my homestead. My eyes are theirs, and their safety is in my hands."','SIXMOREVODKA','Avarosan Sentry','01FR003','[''Last Breath'']','[''LastBreath'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (416,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI055.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI055-full.png''}]','Shadow Isles','ShadowIsles',3,6,7,NULL,NULL,NULL,NULL,'"As our ships near those haunted lands, I ponder this: did those nightmarish creations originate on these twisted shores? Did they ever truly live?" - Arie Wrence, Demacian Soldier','SIXMOREVODKA','Soulgorger','01SI055','[''Lifesteal'']','[''Lifesteal'']',NULL,NULL,'RARE','Rare',NULL,'[]',NULL,'Unit',1,'Set1');
INSERT INTO "API" VALUES (417,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI047.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01SI047-full.png''}]','Shadow Isles','ShadowIsles',0,0,0,'Pick a follower. Create an <link=keyword.Ephemeral><sprite name=Ephemeral><style=Keyword>Ephemeral</style></link> copy of it in hand.','Pick a follower. Create an Ephemeral copy of it in hand.',NULL,NULL,'For a moment, she remembered. Dappled sunlight dancing across her skin, plump dewberries bursting between her teeth, and the glade’s fragile melody drifting over her on the breeze. Then... it was gone.','Kudos Productions','Fading Memories','01SI047','[''Burst'']','[''Burst'']','Burst','Burst','RARE','Rare',NULL,'[]',NULL,'Spell',1,'Set1');
INSERT INTO "API" VALUES (418,'[]','[]','[{''gameAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE030.png'', ''fullAbsolutePath'': ''http://dd.b.pvp.net/1_8_0/set1/en_us/img/cards/01DE030-full.png''}]','Demacia','Demacia',2,4,3,NULL,NULL,NULL,NULL,'Arrows rained down from the fortress walls in droves, but none could touch that fleck of silver darting through the sky. ','SIXMOREVODKA','Silverwing Diver','01DE030','[''Elusive'', ''Tough'']','[''Elusive'', ''Tough'']',NULL,NULL,'COMMON','Common',NULL,'[]',NULL,'Unit',1,'Set1');
